'use client';

import React, { useState, useEffect } from 'react';
import { UserPointsWidget } from '@/features/community/gamification/components/UserPointsWidget';
import { BadgesDisplay } from '@/features/community/gamification/components/BadgesDisplay';
import { Leaderboard } from '@/features/community/gamification/components/Leaderboard';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Trophy } from 'lucide-react';

export default function GamificationPage() {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // In a real app, you might fetch all data here or let sub-components fetch their own
  // For simplicity, we'll assume sub-components handle their own fetching from the mock service

  useEffect(() => {
    // Simulate a brief loading for the page itself
    const timer = setTimeout(() => {
      setLoading(false);
    }, 500);
    return () => clearTimeout(timer);
  }, []);

  if (loading) {
    return <div className="text-center py-8">Loading Gamification Dashboard...</div>;
  }

  if (error) {
    return <div className="text-center py-8 text-red-500">Error: {error}</div>;
  }

  return (
    <div className="space-y-8">
      <h1 className="text-3xl font-bold flex items-center">
        <Trophy className="mr-2" /> Gamification Dashboard
      </h1>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-1">
          <UserPointsWidget />
        </div>
        <div className="lg:col-span-2">
          <BadgesDisplay />
        </div>
      </div>

      <Leaderboard />
    </div>
  );
}

'use client';

import React, { ReactNode, Suspense, useEffect } from 'react';
import { cn } from '@/shared/utils';
import { LayoutProvider, useLayout } from '@/core/providers/LayoutContext';
import { HeaderProvider } from '@/core/providers/HeaderContext';
import { useLayoutStore } from '@/core/stores/useLayoutStore';
import { useTheme } from '@/app/providers';
import AppErrorBoundary from '@/features/security/components/AppErrorBoundary';
import { LoadingSpinner } from '@/shared/components/ui/loading-spinner';
import { Sidebar } from '@/core/app/components/layout/AppSidebar';
import { AppHeader } from '@/core/app/components/layout/AppHeader';
import { AppFooter } from '@/core/app/components/layout/AppFooter';
import { useSession } from 'next-auth/react';
import { usePathname } from 'next/navigation';
import { usePermissions } from '@/features/auth/hooks/usePermissions';
import { useContextAwareNavigation } from '@/features/auth/hooks/useContextAwareNavigation';
import { SyncStatusBanner } from '@/shared/components/layout/SyncStatusBanner';
import { getDeadlines } from '@/core/app/services/dashboardService';
import { useFetchNotifications } from '@/features/community/useFetchNotifications';
import { NOTIFICATIONS_REFRESH_EVENT } from '@/features/community/notificationEvents';
import { useAuthStore } from '@/features/auth/store/useAuthStore';
import { usePageHeader } from '@/core/providers/HeaderContext';

interface AppLayoutProps {
  children: ReactNode;
}

const AppLayoutContent: React.FC<AppLayoutProps> = ({ children }) => {
  const { data: session, status } = useSession();
  const { toggleTheme } = useLayout();
  const { colorScheme } = useTheme();
  const { contextAwareNavigation } = useContextAwareNavigation();
  const { sidebarOpen, setSidebarOpen, setNotificationsOpen, notificationsOpen } = useLayoutStore();

  // Sync NextAuth session into the Zustand auth store so existing consumers
  // that use `useAuthStore` remain consistent with NextAuth's session state.
  useEffect(() => {
    if (status === 'loading') return;
    if (session?.user) {
      useAuthStore.setState({ user: session.user as any, isAuthenticated: true });
    } else {
      useAuthStore.setState({ user: null, isAuthenticated: false });
    }
  }, [session, status]);

  const user = session?.user;
  const { data: notifications = [], refetch } = useFetchNotifications();

  // Fetch deadlines and rely on react-query for notifications.
  useEffect(() => {
    if (!session?.user) return;

    const fetchDeadlines = async () => {
      try {
        const dl = await getDeadlines();
      } catch (error) {
        console.error('Failed to fetch deadlines:', error);
      }
    };

    fetchDeadlines();
    // Intentionally do not poll notifications here. Notifications are cached for 1 hour
    // (see useFetchNotifications) and can be refreshed via the header or external triggers.
  }, [session?.user]);

  const refreshNotifications = () => {
    try {
      refetch();
    } catch (err) {
      // ignore
    }
  };

  // Listen for external refresh triggers (e.g. WebSocket / Service Worker / push) and refetch
  useEffect(() => {
    const handler = () => {
      try {
        refetch();
      } catch {}
    };
    window.addEventListener(NOTIFICATIONS_REFRESH_EVENT, handler);
    return () => window.removeEventListener(NOTIFICATIONS_REFRESH_EVENT, handler);
  }, [refetch]);

  // Close mobile sidebar when the route/pathname changes
  const pathname = usePathname();
  useEffect(() => {
    // Close the mobile sidebar when the route/pathname changes.
    // Do not depend on `sidebarOpen` here — that would cause the effect to
    // run when the drawer is toggled and immediately close it again.
    setSidebarOpen(false);
  }, [pathname, setSidebarOpen]);

  if (status === 'loading') {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <LoadingSpinner size="lg" />
      </div>
    );
  }

  return (
    <AppErrorBoundary>
      {/* Mobile overlay backdrop (z-40) */}
      {sidebarOpen && (
        <div
          className="lg:hidden fixed inset-0 z-40 bg-black bg-opacity-50"
          onClick={() => setSidebarOpen(false)}
          aria-hidden="true"
        />
      )}

      <div className="flex min-h-screen bg-gray-50 dark:bg-gray-900">
        <Sidebar theme={colorScheme} user={user} navigationItems={contextAwareNavigation} />

        {/* Main app column (center) */}
        <div className="flex-1 flex flex-col overflow-hidden">
          <AppHeader
            theme={colorScheme}
            toggleTheme={toggleTheme}
            user={user}
            notifications={notifications}
            notificationsOpen={notificationsOpen}
            setNotificationsOpen={setNotificationsOpen}
            onNotificationRefresh={refreshNotifications}
          />

          {/* content area - Adjusted padding to avoid overlap with sticky header */}
          <div className="flex-1 overflow-auto">
            <div
              className={cn(
                `w-full px-3 sm:px-4 md:px-6 lg:px-8 py-4 lg:py-6 transition-all duration-300 pt-0`, // No top padding; rely on dashboard's pt if needed
                sidebarOpen && 'lg:pl-0' // Adjust for sidebar if open on desktop (unlikely)
              )}
            >
              <main className={cn('flex-1 py-2 transition-all duration-300 min-w-0')}>
                <div className="space-y-6">
                  <Suspense fallback={<LoadingSpinner />}>{children}</Suspense>
                </div>
              </main>
            </div>
          </div>

          <AppFooter />
        </div>
      </div>
    </AppErrorBoundary>
  );
};

const AppLayout: React.FC<AppLayoutProps> = ({ children }) => {
  return (
    <LayoutProvider>
      <HeaderProvider>
        <AppLayoutContent>{children}</AppLayoutContent>
      </HeaderProvider>
    </LayoutProvider>
  );
};

export default AppLayout;

