'use client';

import React, { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import useRequireAuth from '@/features/auth/hooks/useRequireAuth';
import { ArrowLeft, Download, File, Share, Trash } from 'lucide-react';
import materialService from '@/features/courses/services/materialService';

interface Material {
  id: string;
  title: string;
  description?: string;
  type?: string;
  author?: string;
  uploadDate?: string;
  size?: string;
  url?: string;
  content?: string;
}

export default function MaterialViewPage({ params }: { params: Promise<{ id: string }> }) {
  const { isLoading } = useRequireAuth();
  const router = useRouter();
  const [material, setMaterial] = useState<Material | null>(null);
  const [isLoadingMaterial, setIsLoadingMaterial] = useState(true);
  const [error, setError] = useState('');
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [materialId, setMaterialId] = useState<string>('');

  useEffect(() => {
    const initializeParams = async () => {
      const resolvedParams = await params;
      setMaterialId(resolvedParams.id);
    };
    initializeParams();
  }, [params]);

  useEffect(() => {
    if (!materialId) return;

    const fetchMaterial = async () => {
      try {
        setIsLoadingMaterial(true);

        try {
          // Try to fetch from the real API
          const data = await materialService.getMaterialById(materialId);
          setMaterial(data);
        } catch (apiError) {
          console.warn('API fetch failed, using fallback:', apiError);

          // Fallback to mock data
          // In a real app, you would handle this differently
          const mockMaterial: Material = {
            id: materialId,
            title: 'Sample Study Material',
            description: 'This is a sample study material for demonstration purposes.',
            type: 'pdf',
            author: 'Dr. John Doe',
            uploadDate: new Date().toISOString(),
            size: '2.4 MB',
            url: '/sample.pdf',
            content: `
              # Sample Study Notes

              ## Introduction

              These are sample study notes for demonstration purposes. In a real application, this would be the actual content of your notes.

              ## Key Points

              1. First important point about the topic
              2. Second important point about the topic
              3. Third important point about the topic

              ## Summary

              This is a summary of the study material. It covers the main points and provides a concise overview of the topic.
            `,
          };

          setMaterial(mockMaterial);
        }
      } catch (error) {
        console.error('Error fetching material:', error);
        setError('Failed to load material. Please try again.');
      } finally {
        setIsLoadingMaterial(false);
      }
    };

    fetchMaterial();
  }, [materialId]);

  const handleDelete = async () => {
    if (!material) return;

    try {
      await materialService.deleteMaterial(material.id);
      router.push('/materials');
    } catch (error) {
      console.error('Error deleting material:', error);
      setError('Failed to delete material. Please try again.');
      setShowDeleteConfirm(false);
    }
  };

  const handleDownload = () => {
    if (!material?.url) return;

    // Create a temporary link element
    const link = document.createElement('a');
    link.href = material.url;
    link.download = `${material.title}.${material.type}`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleShare = () => {
    if (!material) return;

    // Use the Web Share API if available
    if (navigator.share) {
      navigator
        .share({
          title: material.title,
          text: material.description,
          url: window.location.href,
        })
        .catch(error => {
          console.error('Error sharing:', error);
        });
    } else {
      // Fallback to copying the URL to clipboard
      navigator.clipboard
        .writeText(window.location.href)
        .then(() => {
          alert('Link copied to clipboard!');
        })
        .catch(error => {
          console.error('Error copying to clipboard:', error);
        });
    }
  };

  const renderContent = () => {
    if (!material) return null;

    // For text-based content
    if (material.content) {
      return (
        <div className="prose max-w-none">
          <pre className="whitespace-pre-wrap">{material.content}</pre>
        </div>
      );
    }

    // For PDFs
    if (material.type === 'pdf' && material.url) {
      return (
        <div className="w-full h-[70vh]">
          <iframe src={material.url} className="w-full h-full border-0" title={material.title} />
        </div>
      );
    }

    // For images
    if (['jpg', 'jpeg', 'png'].includes(material.type || '') && material.url) {
      return (
        <div className="flex justify-center">
          <img
            src={material.url}
            alt={material.title}
            className="max-w-full max-h-[70vh] object-contain"
          />
        </div>
      );
    }

    // For other file types
    return (
      <div className="text-center py-10">
        <File className="h-16 w-16 mx-auto text-gray-400" />
        <h3 className="mt-2 text-lg font-medium text-gray-900">Preview not available</h3>
        <p className="mt-1 text-sm text-gray-500">
          This file type cannot be previewed. Please download the file to view it.
        </p>
        <Button variant="default" size="sm" className="mt-4" onClick={handleDownload}>
          <Download className="h-4 w-4 mr-2" />
          Download
        </Button>
      </div>
    );
  };

  if (isLoading || isLoadingMaterial) {
    return (
      <div className="flex items-center justify-center min-h-[80vh]">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-blue-500"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="text-center py-10">
        <div className="text-red-500 mb-4">{error}</div>
        <Button variant="secondary" onClick={() => router.push('/materials')}>
          <ArrowLeft className="h-4 w-4 mr-2" />
          Back to Materials
        </Button>
      </div>
    );
  }

  if (!material) {
    return (
      <div className="text-center py-10">
        <h3 className="text-lg font-medium text-gray-900">Material not found</h3>
        <Button variant="secondary" onClick={() => router.push('/materials')} className="mt-4">
          <ArrowLeft className="h-4 w-4 mr-2" />
          Back to Materials
        </Button>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <Button variant="secondary" onClick={() => router.push('/materials')}>
          <ArrowLeft className="h-4 w-4 mr-2" />
          Back
        </Button>

        <div className="flex space-x-2">
          <Button variant="secondary" onClick={handleShare}>
            <Share className="h-4 w-4 mr-2" />
            Share
          </Button>

          <Button variant="secondary" onClick={handleDownload}>
            <Download className="h-4 w-4 mr-2" />
            Download
          </Button>

          <Button variant="destructive" onClick={() => setShowDeleteConfirm(true)}>
            <Trash className="h-4 w-4 mr-2" />
            Delete
          </Button>
        </div>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>{material.title}</CardTitle>
          {material.description && <p className="text-gray-500 mt-1">{material.description}</p>}
          <div className="flex flex-wrap gap-4 text-sm text-gray-500 mt-2">
            {material.author && <div>Author: {material.author}</div>}
            {material.uploadDate && (
              <div>Uploaded: {new Date(material.uploadDate).toLocaleDateString()}</div>
            )}
            {material.size && <div>Size: {material.size}</div>}
            {material.type && <div>Type: {material.type.toUpperCase()}</div>}
          </div>
        </CardHeader>
        <CardContent>{renderContent()}</CardContent>
      </Card>

      {/* Delete Confirmation Dialog */}
      {showDeleteConfirm && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white p-6 rounded-lg max-w-md w-full">
            <h3 className="text-lg font-medium mb-4">Delete Material</h3>
            <p className="text-gray-500 mb-4">
              Are you sure you want to delete "{material.title}"? This action cannot be undone.
            </p>
            <div className="flex justify-end space-x-2">
              <Button variant="secondary" onClick={() => setShowDeleteConfirm(false)}>
                Cancel
              </Button>
              <Button variant="destructive" onClick={handleDelete}>
                Delete
              </Button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// frontend/src/app/(app)/notifications/page.tsx

'use client';

import React, { useEffect, useState } from 'react';
import {
  markAllNotificationsAsRead,
  markNotificationAsRead,
  deleteNotification,
} from '@/features/community/notificationService';
import { Notification } from '@/shared/types/notificationsInterface';
import { useFetchNotifications } from '@/features/community/useFetchNotifications';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Bell, CheckCircle, Trash2 } from 'lucide-react';

export default function NotificationsPage() {
  const { data: notifications = [], refetch, isLoading, isError } = useFetchNotifications();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleMarkAllAsRead = async () => {
    try {
      await markAllNotificationsAsRead();
      refetch(); // Re-fetch to update UI
    } catch (err) {
      console.error('Failed to mark all as read:', err);
    }
  };

  const handleMarkAsRead = async (id: string) => {
    try {
      await markNotificationAsRead(id);
      refetch(); // Re-fetch to update UI
    } catch (err) {
      console.error('Failed to mark notification as read:', err);
    }
  };

  const handleDeleteNotification = async (id: string) => {
    try {
      await deleteNotification(id);
      refetch(); // Re-fetch to update UI
    } catch (err: any) {
      console.error('Failed to delete notification:', err);
      setError(err.response?.data?.message || 'Failed to delete notification.');
    }
  };

  const getTimeAgo = (dateString: string) => {
    const date = new Date(dateString);
    const now = new Date();
    const seconds = Math.floor((now.getTime() - date.getTime()) / 1000);

    if (seconds < 60) return `${seconds} seconds ago`;

    const minutes = Math.floor(seconds / 60);
    if (minutes < 60) return `${minutes} minute${minutes !== 1 ? 's' : ''} ago`;

    const hours = Math.floor(minutes / 60);
    if (hours < 24) return `${hours} hour${hours !== 1 ? 's' : ''} ago`;

    const days = Math.floor(hours / 24);
    if (days < 30) return `${days} day${days !== 1 ? 's' : ''} ago`;

    const months = Math.floor(days / 30);
    if (months < 12) return `${months} month${months !== 1 ? 's' : ''} ago`;

    const years = Math.floor(months / 12);
    return `${years} year${years !== 1 ? 's' : ''} ago`;
  };

  if (loading) {
    return <div className="text-center py-8">Loading Notifications...</div>;
  }

  if (error) {
    return <div className="text-center py-8 text-red-500">Error: {error}</div>;
  }

  const unreadNotifications = notifications.filter(n => !n.read);
  const readNotifications = notifications.filter(n => n.read);

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-center">
        <h1 className="text-3xl font-bold">Notifications</h1>
        {unreadNotifications.length > 0 && (
          <Button onClick={handleMarkAllAsRead} variant="outline">
            <CheckCircle className="mr-2 h-4 w-4" /> Mark All as Read
          </Button>
        )}
      </div>

      {notifications.length === 0 ? (
        <Card>
          <CardContent className="p-6 text-center text-muted-foreground">
            <Bell className="mx-auto h-12 w-12 text-gray-400 mb-4" />
            <p>You don't have any notifications yet.</p>
          </CardContent>
        </Card>
      ) : (
        <div className="grid gap-4">
          {unreadNotifications.length > 0 && (
            <Card>
              <CardHeader>
                <CardTitle>Unread ({unreadNotifications.length})</CardTitle>
              </CardHeader>
              <CardContent className="grid gap-4">
                {unreadNotifications.map(notification => (
                  <div
                    key={notification.id}
                    className="flex items-start p-4 border rounded-md bg-blue-50 dark:bg-blue-900/20"
                  >
                    <Bell className="h-5 w-5 text-blue-600 mr-3 shrink-0" />
                    <div className="flex-1">
                      <p className="font-medium">{notification.title}</p>
                      <p className="text-sm text-muted-foreground">{notification.message}</p>
                      <p className="text-xs text-gray-500 mt-1">
                        {getTimeAgo(notification.createdAt)}
                      </p>
                      <div className="mt-2 space-x-2">
                        <Button size="sm" onClick={() => handleMarkAsRead(notification.id)}>
                          Mark as Read
                        </Button>
                        <Button
                          size="sm"
                          variant="destructive"
                          onClick={() => handleDeleteNotification(notification.id)}
                        >
                          Delete
                        </Button>
                      </div>
                    </div>
                  </div>
                ))}
              </CardContent>
            </Card>
          )}

          {readNotifications.length > 0 && (
            <Card>
              <CardHeader>
                <CardTitle>Read ({readNotifications.length})</CardTitle>
              </CardHeader>
              <CardContent className="grid gap-4">
                {readNotifications.map(notification => (
                  <div key={notification.id} className="flex items-start p-4 border rounded-md">
                    <CheckCircle className="h-5 w-5 text-green-600 mr-3 shrink-0" />
                    <div className="flex-1">
                      <p className="font-medium">{notification.title}</p>
                      <p className="text-sm text-muted-foreground">{notification.message}</p>
                      <p className="text-xs text-gray-500 mt-1">
                        {getTimeAgo(notification.createdAt)}
                      </p>
                      <div className="mt-2">
                        <Button
                          size="sm"
                          variant="destructive"
                          onClick={() => handleDeleteNotification(notification.id)}
                        >
                          Delete
                        </Button>
                      </div>
                    </div>
                  </div>
                ))}
              </CardContent>
            </Card>
          )}
        </div>
      )}
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useAuthStore } from '@/features/auth/store/useAuthStore';
import { apiService } from '@/features/auth/services/apiClient';
import AppErrorBoundary from '@/features/security/components/AppErrorBoundary';
import { LoadingSpinner } from '@/shared/components/ui/loading-spinner';
import { Card } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button'; // Standardized casing
import { toast } from 'sonner';
import { Trophy, Star, Target, Zap, BookOpen, Clock } from 'lucide-react';

interface Achievement {
  id: string;
  title: string;
  description: string;
  icon: string;
  progress: number;
  completed: boolean;
  completedAt?: string;
  type: 'quiz' | 'study' | 'streak' | 'milestone';
  points: number;
}

interface AchievementStats {
  totalAchievements: number;
  completedAchievements: number;
  totalPoints: number;
  rank: string;
  nextRank: {
    name: string;
    pointsNeeded: number;
  };
}

export default function AchievementsPage() {
  const router = useRouter();
  const { user } = useAuthStore();
  const [loading, setLoading] = useState(true);
  const [achievements, setAchievements] = useState<Achievement[]>([]);
  const [stats, setStats] = useState<AchievementStats>({
    totalAchievements: 0,
    completedAchievements: 0,
    totalPoints: 0,
    rank: 'Beginner',
    nextRank: {
      name: 'Intermediate',
      pointsNeeded: 100,
    },
  });

  useEffect(() => {
    const fetchAchievements = async () => {
      try {
        const [achievementsResponse, statsResponse] = await Promise.all([
          apiService.get<Achievement[]>('/users/achievements'),
          apiService.get<AchievementStats>('/users/achievement-stats'),
        ]);
        setAchievements(achievementsResponse.data);
        setStats(statsResponse.data);
      } catch (error) {
        toast.error('Failed to load achievements');
      } finally {
        setLoading(false);
      }
    };

    fetchAchievements();
  }, []);

  const getAchievementIcon = (type: Achievement['type']) => {
    switch (type) {
      case 'quiz':
        return <Target className="w-8 h-8 text-blue-500" />;
      case 'study':
        return <BookOpen className="w-8 h-8 text-green-500" />;
      case 'streak':
        return <Zap className="w-8 h-8 text-yellow-500" />;
      case 'milestone':
        return <Star className="w-8 h-8 text-purple-500" />;
      default:
        return <Trophy className="w-8 h-8 text-gray-500" />;
    }
  };

  if (loading) {
    return <LoadingSpinner />;
  }

  return (
    <AppErrorBoundary>
      <div className="container mx-auto px-4 py-8">
        <h1 className="text-3xl font-bold mb-8">Achievements</h1>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
          <Card className="p-4">
            <div className="flex items-center space-x-4">
              <Trophy className="w-8 h-8 text-yellow-500" />
              <div>
                <p className="text-sm text-gray-500">Total Points</p>
                <p className="text-2xl font-bold">{stats.totalPoints}</p>
              </div>
            </div>
          </Card>
          <Card className="p-4">
            <div className="flex items-center space-x-4">
              <Star className="w-8 h-8 text-blue-500" />
              <div>
                <p className="text-sm text-gray-500">Current Rank</p>
                <p className="text-2xl font-bold">{stats.rank}</p>
              </div>
            </div>
          </Card>
          <Card className="p-4">
            <div className="flex items-center space-x-4">
              <Target className="w-8 h-8 text-green-500" />
              <div>
                <p className="text-sm text-gray-500">Achievements</p>
                <p className="text-2xl font-bold">
                  {stats.completedAchievements}/{stats.totalAchievements}
                </p>
              </div>
            </div>
          </Card>
          <Card className="p-4">
            <div className="flex items-center space-x-4">
              <Clock className="w-8 h-8 text-purple-500" />
              <div>
                <p className="text-sm text-gray-500">Next Rank</p>
                <p className="text-2xl font-bold">{stats.nextRank.name}</p>
                <p className="text-sm text-gray-500">{stats.nextRank.pointsNeeded} points needed</p>
              </div>
            </div>
          </Card>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {achievements.map(achievement => (
            <Card
              key={achievement.id}
              className={`p-6 ${achievement.completed ? 'border-green-500' : 'border-gray-200'}`}
            >
              <div className="flex items-start space-x-4">
                <div className="shrink-0">{getAchievementIcon(achievement.type)}</div>
                <div className="flex-1">
                  <h3 className="text-lg font-semibold">{achievement.title}</h3>
                  <p className="text-sm text-gray-500 mt-1">{achievement.description}</p>
                  <div className="mt-4">
                    <div className="flex justify-between text-sm text-gray-500 mb-1">
                      <span>Progress</span>
                      <span>{achievement.progress}%</span>
                    </div>
                    <div className="w-full bg-gray-200 rounded-full h-2">
                      <div
                        className="bg-blue-500 h-2 rounded-full"
                        style={{ width: `${achievement.progress}%` }}
                      />
                    </div>
                  </div>
                  {achievement.completed && (
                    <div className="mt-4 flex items-center text-sm text-green-500">
                      <Trophy className="w-4 h-4 mr-1" />
                      Completed
                      {achievement.completedAt && (
                        <span className="ml-2 text-gray-500">
                          on {new Date(achievement.completedAt).toLocaleDateString()}
                        </span>
                      )}
                    </div>
                  )}
                  <div className="mt-4 flex items-center text-sm text-gray-500">
                    <Star className="w-4 h-4 mr-1" />
                    {achievement.points} points
                  </div>
                </div>
              </div>
            </Card>
          ))}
        </div>

        {achievements.length === 0 && (
          <Card className="p-6 text-center">
            <p className="text-gray-500">No achievements found</p>
            <Button className="mt-4" onClick={() => router.push('/courses')}>
              Start Learning
            </Button>
          </Card>
        )}
      </div>
    </AppErrorBoundary>
  );
}

'use client';

import React, { useEffect, useState } from 'react';
import { useSession } from 'next-auth/react';
import { Card, CardContent, CardHeader, CardTitle } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import useRequireAuth from '@/features/auth/hooks/useRequireAuth';
import { Camera, User } from 'lucide-react';
import { userService } from '@/features/profile/services/userService';
import { useRouter } from 'next/navigation';

// Local shape used by this form — keep it lightweight and decoupled from
// backend DTOs to avoid tight coupling with server types.
interface LocalUserProfile {
  name: string;
  email: string;
  bio?: string;
  specialization?: string;
  year?: string;
  institution?: string;
  location?: string;
  phone?: string;
  avatar?: string | null;
}

export default function EditProfilePage() {
  const { isLoading, session } = useRequireAuth();
  const router = useRouter();

  const [profile, setProfile] = useState<LocalUserProfile>({
    name: '',
    email: '',
    bio: '',
    specialization: '',
    year: '',
    institution: '',
    location: '',
    phone: '',
    avatar: null,
  });

  const [isSaving, setIsSaving] = useState(false);
  const [saveMessage, setSaveMessage] = useState('');
  const [fieldErrors, setFieldErrors] = useState<Record<string, string[]>>({});
  const [previewImage, setPreviewImage] = useState<string | null>(null);

  useEffect(() => {
    const fetchProfile = async () => {
      if (session?.user?.id) {
        try {
          const userProfile = await userService.getUserProfile(session.user.id);
          if (!userProfile) {
            setSaveMessage('Profile data not found');
            return;
          }
          const firstName = userProfile.firstName || '';
          const lastName = userProfile.lastName || '';
          // Compose name, trim to avoid ' '
          const name = (firstName + ' ' + lastName).trim();
          setProfile({
            name,
            email: userProfile.email || '',
            bio: userProfile.bio || '',
            specialization: userProfile.specialization || '',
            year: userProfile.yearOfExperience ? String(userProfile.yearOfExperience) : '',
            institution: userProfile.institution || '',
            location: userProfile.location || '',
            phone: userProfile.phone || '',
            avatar: userProfile.profileImage || null, // Use profileImage from backend
          });
          setPreviewImage(userProfile.profileImage || null);
        } catch (error: any) {
          // Log extra details only in development to avoid noisy logs in prod
          if (process.env.NODE_ENV !== 'production') {
            console.error('Error fetching profile:', {
              message: error?.message,
              response: error?.response?.data,
              stack: error?.stack,
            });
          }
          setSaveMessage('Error fetching profile');
        }
      }
    };

    fetchProfile();
  }, [session]);

  const handleChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>
  ) => {
    const { name, value } = e.target;
    setProfile(prev => ({ ...prev, [name]: value }));
    // Clear field-level errors for this UI field when user edits it
    setFieldErrors(prev => {
      const copy = { ...prev };
      delete copy[name];
      return copy;
    });
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setPreviewImage(reader.result as string);
        // Optionally, update profile.avatar here if you want to send it to the backend immediately or on save
        setProfile(prev => ({ ...prev, avatar: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveProfile = async () => {
    setIsSaving(true);
    setSaveMessage('');

    try {
      if (!session?.user?.id) {
        setSaveMessage('Error: User not authenticated');
        return;
      }

      const nameParts = profile.name.trim().split(' ');
      const firstName = nameParts.shift() || '';
      const lastName = nameParts.join(' ') || '';

      // Map to backend UpdateUserDto expected fields
      const updatePayload: Record<string, any> = {
        firstName,
        lastName,
        bio: profile.bio || undefined,
        location: profile.location || undefined,
        phone: profile.phone || undefined,
        profileImage: profile.avatar || undefined, // Send avatar as profileImage
        institution: profile.institution || undefined,
        specialization: profile.specialization || undefined,
        yearOfExperience: profile.year ? Number(profile.year) : undefined,
      };

      await userService.updateUserProfile(session.user.id, updatePayload);

      setSaveMessage('Profile saved successfully');
      setFieldErrors({});
      setTimeout(() => setSaveMessage(''), 3000);
      router.push('/profile'); // Redirect back to display page
    } catch (error: any) {
      // Try to surface server validation errors if available
      const resp = error?.response?.data;
      let friendly = 'Error saving profile';
      if (resp) {
        // Common NestJS/axios shapes: { message: '...', statusCode: 400 } or { message: ['a','b'] }
        if (Array.isArray(resp.message)) {
          friendly = resp.message.join('; ');
        } else if (typeof resp.message === 'string') {
          friendly = resp.message;
        } else if (resp.errors) {
          // Validation pipe may return an object with constraints
          try {
            // resp.errors from our backend is an array of { field, errors: [] }
            if (Array.isArray(resp.errors)) {
              const byField: Record<string, string[]> = {};
              (resp.errors as any[]).forEach(err => {
                const field = err.field || err.property || err.name;
                const errs = err.errors || err.constraints || err.messages || [];
                byField[field] = Array.isArray(errs) ? errs : [String(errs)];
              });

              // Map backend field names to our UI input names (e.g., firstName/lastName -> name)
              const mapField = (backendField: string) => {
                if (!backendField) return backendField;
                if (['firstName', 'lastName'].includes(backendField)) return 'name';
                if (backendField === 'phoneNumber' || backendField === 'phone') return 'phone';
                if (backendField === 'profileImage') return 'avatar';
                if (backendField === 'yearOfExperience') return 'year';
                return backendField;
              };

              const uiErrors: Record<string, string[]> = {};
              Object.entries(byField).forEach(([k, v]) => {
                const uiKey = mapField(k) || k;
                uiErrors[uiKey] = (uiErrors[uiKey] || []).concat(v as string[]);
              });

              setFieldErrors(uiErrors);

              const all = Object.values(byField).flatMap(v => v as string[]);
              if (all.length) friendly = all.join('; ');
            } else {
              const all = Object.values(resp.errors || {}).flatMap((v: any) =>
                v?.constraints ? Object.values(v.constraints) : []
              );
              if (all.length) friendly = all.join('; ');
            }
          } catch {}
        }
      } else if (error?.message) {
        friendly = error.message;
      }

      // Emit structured debug information in development only. Axios/Nest
      // error objects can be empty when stringified; include response.data
      // so developers see validation errors without exposing them in prod.
      if (process.env.NODE_ENV !== 'production') {
        console.error('Error saving profile:', {
          message: error?.message,
          response: error?.response?.data,
          status: error?.response?.status,
          stack: error?.stack,
        });
      }
      setSaveMessage(friendly);
    } finally {
      setIsSaving(false);
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-[80vh]">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-blue-500"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-3xl font-bold">Edit Profile</h1>
        <Button variant="outline" onClick={() => router.push('/profile')}>
          Cancel
        </Button>
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center">
            <User className="h-5 w-5 mr-2" />
            Personal Information
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-1 gap-6 md:grid-cols-2">
            <div className="md:col-span-2 flex flex-col items-center mb-4">
              <div className="relative">
                <div className="h-32 w-32 rounded-full bg-gray-200 flex items-center justify-center text-gray-600 text-4xl font-bold overflow-hidden">
                  {previewImage ? (
                    <img src={previewImage} alt="Profile" className="h-full w-full object-cover" />
                  ) : (
                    profile.name.charAt(0) || 'U'
                  )}
                </div>
                <label
                  htmlFor="avatar-upload"
                  className="absolute bottom-0 right-0 bg-blue-500 text-white p-2 rounded-full cursor-pointer"
                >
                  <Camera className="h-4 w-4" />
                  <input
                    id="avatar-upload"
                    type="file"
                    accept="image/*"
                    className="hidden"
                    onChange={handleImageChange}
                    aria-label="Upload profile picture"
                  />
                </label>
              </div>
              <p className="text-sm text-gray-500 mt-2">
                Click the camera icon to upload a profile picture
              </p>
            </div>

            <div>
              <label htmlFor="name" className="block text-sm font-medium mb-1">
                Full Name
              </label>
              <input
                type="text"
                name="name"
                className="w-full px-3 py-2 border border-gray-300 rounded-md"
                value={profile.name}
                onChange={handleChange}
                placeholder="Enter your full name"
              />
              {fieldErrors.name && (
                <p className="text-xs text-red-600 mt-1">{fieldErrors.name.join('; ')}</p>
              )}
            </div>

            <div>
              <label htmlFor="email" className="block text-sm font-medium mb-1">
                Email
              </label>
              <input
                id="email"
                type="email"
                name="email"
                className="w-full px-3 py-2 border border-gray-300 rounded-md bg-gray-100"
                value={profile.email}
                readOnly
                placeholder="Your email address"
              />
              <p className="text-xs text-gray-500 mt-1">Email cannot be changed</p>
            </div>

            <div className="md:col-span-2">
              <label htmlFor="bio" className="block text-sm font-medium mb-1">
                Bio
              </label>
              <textarea
                id="bio"
                name="bio"
                rows={4}
                className="w-full px-3 py-2 border border-gray-300 rounded-md"
                value={profile.bio}
                onChange={handleChange}
                placeholder="Tell us about yourself..."
              />
              {fieldErrors.bio && (
                <p className="text-xs text-red-600 mt-1">{fieldErrors.bio.join('; ')}</p>
              )}
            </div>

            <div>
              <label htmlFor="phone" className="block text-sm font-medium mb-1">
                Phone Number
              </label>
              <input
                id="phone"
                type="tel"
                name="phone"
                className="w-full px-3 py-2 border border-gray-300 rounded-md"
                value={profile.phone}
                onChange={handleChange}
                placeholder="Enter your phone number"
              />
              {fieldErrors.phone && (
                <p className="text-xs text-red-600 mt-1">{fieldErrors.phone.join('; ')}</p>
              )}
            </div>

            <div>
              <label className="block text-sm font-medium mb-1">Location</label>
              <input
                type="text"
                name="location"
                className="w-full px-3 py-2 border border-gray-300 rounded-md"
                value={profile.location}
                onChange={handleChange}
                placeholder="City, Country"
              />
              {fieldErrors.location && (
                <p className="text-xs text-red-600 mt-1">{fieldErrors.location.join('; ')}</p>
              )}
            </div>
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle>Academic Information</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-1 gap-6 md:grid-cols-2">
            <div>
              <label className="block text-sm font-medium mb-1">Institution</label>
              <input
                type="text"
                name="institution"
                className="w-full px-3 py-2 border border-gray-300 rounded-md"
                value={profile.institution}
                onChange={handleChange}
                placeholder="University or Medical School"
              />
              {fieldErrors.institution && (
                <p className="text-xs text-red-600 mt-1">{fieldErrors.institution.join('; ')}</p>
              )}
            </div>

            <div>
              <label htmlFor="year" className="block text-sm font-medium mb-1">
                Year
              </label>
              <select
                id="year"
                name="year"
                className="w-full px-3 py-2 border border-gray-300 rounded-md"
                value={profile.year}
                onChange={handleChange}
                title="Select your current year of study"
              >
                <option value="">Select Year</option>
                <option value="1">1st Year</option>
                <option value="2">2nd Year</option>
                <option value="3">3rd Year</option>
                <option value="4">4th Year</option>
                <option value="5">5th Year</option>
                <option value="6">6th Year</option>
                <option value="resident">Resident</option>
                <option value="fellow">Fellow</option>
                <option value="attending">Attending</option>
              </select>
              {fieldErrors.year && (
                <p className="text-xs text-red-600 mt-1">{fieldErrors.year.join('; ')}</p>
              )}
            </div>
          </div>
        </CardContent>
      </Card>

      <div className="flex justify-end">
        {saveMessage && (
          <div
            className={`mr-4 py-2 px-4 rounded-md ${
              saveMessage.includes('Error')
                ? 'bg-red-100 text-red-700'
                : 'bg-green-100 text-green-700'
            }`}
          >
            {saveMessage}
          </div>
        )}
        <Button
          variant="default"
          onClick={handleSaveProfile}
          disabled={isSaving}
          className={isSaving ? 'opacity-50 cursor-not-allowed' : ''}
        >
          {isSaving ? 'Saving...' : 'Save Profile'}
        </Button>
      </div>
    </div>
  );
}

