'use client';

import { useEffect, useState } from 'react';
import { useQuiz } from '@/shared/hooks/useQuiz';
import { useSession } from 'next-auth/react';
import { Progress } from '@/shared/components/ui/progress';
import { Button } from '@/shared/components/ui/button';
import { Card } from '@/shared/components/ui/card';
import { Alert, AlertDescription } from '@/shared/components/ui/alert';
import { WifiOff, ArrowLeft, ArrowRight, CheckCircle2 } from 'lucide-react';

export default function QuizPage({ params }: { params: Promise<{ unitId: string }> }) {
  const { data: session } = useSession();
  const [unitId, setUnitId] = useState<string>('');

  useEffect(() => {
    params.then(resolvedParams => {
      setUnitId(resolvedParams.unitId);
    });
  }, [params]);

  const {
    questions,
    currentState,
    isLoading,
    error,
    isOffline,
    currentQuestion,
    progress,
    answerQuestion,
    moveToNextQuestion,
    moveToPreviousQuestion,
  } = useQuiz(unitId, session?.user?.id || '');

  useEffect(() => {
    // Register service worker
    if ('serviceWorker' in navigator) {
      navigator.serviceWorker.register('/sw.js').catch(console.error);
    }
  }, []);

  if (!unitId || isLoading) {
    return (
      <div className="container mx-auto p-6">
        <div className="animate-pulse space-y-4">
          <div className="h-8 bg-gray-200 rounded w-1/4"></div>
          <div className="h-32 bg-gray-200 rounded"></div>
          <div className="h-8 bg-gray-200 rounded w-1/2"></div>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="container mx-auto p-6">
        <Alert variant="destructive">
          <AlertDescription>{error.message}</AlertDescription>
        </Alert>
      </div>
    );
  }

  if (!currentQuestion) {
    return (
      <div className="container mx-auto p-6">
        <Alert>
          <AlertDescription>No questions available for this unit.</AlertDescription>
        </Alert>
      </div>
    );
  }

  return (
    <div className="container mx-auto p-6 max-w-3xl">
      {isOffline && (
        <Alert className="mb-4">
          <WifiOff className="h-4 w-4" />
          <AlertDescription>
            You are currently offline. Your answers will be saved locally and synced when you're
            back online.
          </AlertDescription>
        </Alert>
      )}

      <div className="mb-6">
        <Progress value={progress} className="h-2" />
        <p className="text-sm text-gray-500 mt-2">
          Question{' '}
          {(currentState?.currentQuestionIndex !== undefined
            ? currentState.currentQuestionIndex
            : 0) + 1}{' '}
          of {questions.length}
        </p>
      </div>

      <Card className="p-6">
        <h2 className="text-xl font-semibold mb-4">{currentQuestion.question_text}</h2>

        <div className="space-y-3">
          {currentQuestion.options.map((option, index) => (
            <button
              key={index}
              onClick={() => answerQuestion(currentQuestion.id, option)}
              className={`w-full p-4 text-left rounded-lg border transition-colors ${
                currentState?.answers[currentQuestion.id] === option
                  ? 'border-blue-500 bg-blue-50'
                  : 'border-gray-200 hover:border-gray-300'
              }`}
            >
              {option}
            </button>
          ))}
        </div>

        <div className="flex justify-between mt-6">
          <Button
            variant="outline"
            onClick={moveToPreviousQuestion}
            disabled={currentState?.currentQuestionIndex === 0}
          >
            <ArrowLeft className="h-4 w-4 mr-2" />
            Previous
          </Button>

          {currentState?.currentQuestionIndex === questions.length - 1 ? (
            <Button
              onClick={() => {
                // Handle quiz completion
                console.log('Quiz completed!');
              }}
              className="bg-green-600 hover:bg-green-700"
            >
              <CheckCircle2 className="h-4 w-4 mr-2" />
              Complete Quiz
            </Button>
          ) : (
            <Button
              onClick={moveToNextQuestion}
              disabled={!currentState?.answers[currentQuestion.id]}
            >
              Next
              <ArrowRight className="h-4 w-4 ml-2" />
            </Button>
          )}
        </div>
      </Card>
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useAuthStore } from '@/features/auth/store/useAuthStore';
import { apiService } from '@/features/auth/services/apiClient';
import { AppErrorBoundary } from '@/features/security/components/AppErrorBoundary';
import { LoadingSpinner } from '@/shared/components/ui/loading-spinner';
import { Card } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { toast } from 'sonner';
import { Calendar, Clock, Award, BarChart } from 'lucide-react';

interface QuizAttempt {
  id: string;
  quizId: string;
  quizTitle: string;
  score: number;
  totalQuestions: number;
  correctAnswers: number;
  timeSpent: number;
  completedAt: string;
  unitId: string;
  unitTitle: string;
}

interface QuizStats {
  totalAttempts: number;
  averageScore: number;
  bestScore: number;
  totalTimeSpent: number;
  recentImprovement: number;
}

export default function QuizHistoryPage() {
  const router = useRouter();
  const { user } = useAuthStore();
  const [loading, setLoading] = useState(true);
  const [attempts, setAttempts] = useState<QuizAttempt[]>([]);
  const [stats, setStats] = useState<QuizStats>({
    totalAttempts: 0,
    averageScore: 0,
    bestScore: 0,
    totalTimeSpent: 0,
    recentImprovement: 0,
  });

  useEffect(() => {
    const fetchQuizHistory = async () => {
      try {
        const [historyResponse, statsResponse] = await Promise.all([
          apiService.get<QuizAttempt[]>('/quiz/history'),
          apiService.get<QuizStats>('/quiz/stats'),
        ]);
        setAttempts(historyResponse.data);
        setStats(statsResponse.data);
      } catch (error) {
        toast.error('Failed to load quiz history');
      } finally {
        setLoading(false);
      }
    };

    fetchQuizHistory();
  }, []);

  const formatTime = (minutes: number) => {
    const hours = Math.floor(minutes / 60);
    const mins = minutes % 60;
    return hours > 0 ? `${hours}h ${mins}m` : `${mins}m`;
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    });
  };

  if (loading) {
    return <LoadingSpinner />;
  }

  return (
    <AppErrorBoundary>
      <div className="container mx-auto px-4 py-8">
        <h1 className="text-3xl font-bold mb-8">Quiz History</h1>

        {/* Stats Overview */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
          <Card className="p-4">
            <div className="flex items-center space-x-4">
              <Award className="w-8 h-8 text-blue-500" />
              <div>
                <p className="text-sm text-gray-500">Total Attempts</p>
                <p className="text-2xl font-bold">{stats.totalAttempts}</p>
              </div>
            </div>
          </Card>
          <Card className="p-4">
            <div className="flex items-center space-x-4">
              <BarChart className="w-8 h-8 text-green-500" />
              <div>
                <p className="text-sm text-gray-500">Average Score</p>
                <p className="text-2xl font-bold">{stats.averageScore.toFixed(1)}%</p>
              </div>
            </div>
          </Card>
          <Card className="p-4">
            <div className="flex items-center space-x-4">
              <Award className="w-8 h-8 text-yellow-500" />
              <div>
                <p className="text-sm text-gray-500">Best Score</p>
                <p className="text-2xl font-bold">{stats.bestScore}%</p>
              </div>
            </div>
          </Card>
          <Card className="p-4">
            <div className="flex items-center space-x-4">
              <Clock className="w-8 h-8 text-purple-500" />
              <div>
                <p className="text-sm text-gray-500">Total Time</p>
                <p className="text-2xl font-bold">{formatTime(stats.totalTimeSpent)}</p>
              </div>
            </div>
          </Card>
        </div>

        {/* Quiz Attempts List */}
        <div className="space-y-4">
          {attempts.map(attempt => (
            <Card key={attempt.id} className="p-6">
              <div className="flex flex-col md:flex-row md:items-center md:justify-between">
                <div className="space-y-2">
                  <h3 className="text-lg font-semibold">{attempt.quizTitle}</h3>
                  <p className="text-sm text-gray-500">{attempt.unitTitle}</p>
                  <div className="flex items-center space-x-4 text-sm text-gray-500">
                    <div className="flex items-center">
                      <Calendar className="w-4 h-4 mr-1" />
                      {formatDate(attempt.completedAt)}
                    </div>
                    <div className="flex items-center">
                      <Clock className="w-4 h-4 mr-1" />
                      {formatTime(attempt.timeSpent)}
                    </div>
                  </div>
                </div>
                <div className="mt-4 md:mt-0 text-right">
                  <div className="text-2xl font-bold text-blue-600">
                    {((attempt.correctAnswers / attempt.totalQuestions) * 100).toFixed(1)}%
                  </div>
                  <p className="text-sm text-gray-500">
                    {attempt.correctAnswers} of {attempt.totalQuestions} correct
                  </p>
                  <Button
                    variant="outline"
                    className="mt-2"
                    onClick={() => router.push(`/quiz/results/${attempt.id}`)}
                  >
                    View Details
                  </Button>
                </div>
              </div>
            </Card>
          ))}

          {attempts.length === 0 && (
            <Card className="p-6 text-center">
              <p className="text-gray-500">No quiz attempts found</p>
              <Button className="mt-4" onClick={() => router.push('/courses')}>
                Start Learning
              </Button>
            </Card>
          )}
        </div>
      </div>
    </AppErrorBoundary>
  );
}

