'use client';
import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { AuthForm } from '@/features/auth/components/AuthForm';
import { FormField } from '@/features/auth/components/FormField';
import { FormData, FormErrors } from '@/shared/types/authInterface';
import { Role } from '@/shared/enums/role.enum';
import { useToast } from '@/shared/components/ui/use-toast';
import { useAuthStore } from '@/features/auth/store/useAuthStore';

export default function RegisterPage() {
  const router = useRouter();
  const { toast } = useToast();
  const { register, isLoading, error } = useAuthStore();

  useEffect(() => {
    if (error) {
      toast({
        title: 'Error',
        description: error,
        variant: 'destructive',
      });
      useAuthStore.getState().clearError(); // Clear the error after showing the toast
    }
  }, [error, toast]);

  const [formData, setFormData] = useState<FormData>({
    firstName: '', // Changed from name
    lastName: '', // Added
    email: '',
    username: '',
    password: '',
    confirmPassword: '',
    role: 'student',
    acceptTerms: false,
  });

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // Basic client-side validation
    if (formData.password !== formData.confirmPassword) {
      toast({
        title: 'Error',
        description: 'Passwords do not match.',
        variant: 'destructive',
      });
      return;
    }

    if (!formData.acceptTerms) {
      toast({
        title: 'Error',
        description: 'You must accept the terms and conditions.',
        variant: 'destructive',
      });
      return;
    }

    try {
      // Removed name splitting logic
      // const [firstName, ...lastNameParts] = formData.name.split(' ');
      // const lastName = lastNameParts.join(' ') || firstName; // If only one name, use it as last name

      await register({
        email: formData.email,
        password: formData.password,
        firstName: formData.firstName, // Used directly
        lastName: formData.lastName, // Used directly
        username: formData.username,
        role: Role.student, // Default role
        confirmPassword: formData.confirmPassword,
        acceptTerms: formData.acceptTerms, // Add acceptTerms
      });
      router.push('/login?registered=true');
    } catch (err: any) {
      let errorMessage = 'An unexpected error occurred during registration.';
      let fieldErrors: Record<string, string> = {};

      if (err instanceof Error) {
        errorMessage = err.message; // Use the message from the re-thrown Error
      }

      // If there are specific backend validation errors, they might be in a nested structure
      if (err.response && err.response.data) {
        errorMessage = err.response.data.message || errorMessage;
        if (err.response.data.errors) {
          fieldErrors = err.response.data.errors;
        }
      } else if (
        errorMessage.includes('Connection refused') ||
        errorMessage.includes('timed out') ||
        errorMessage.includes('No response received')
      ) {
        errorMessage = `Unable to connect to the authentication service. Please ensure the backend is running and accessible.`;
      }

      if (
        errorMessage.includes('Email or username already exists') ||
        fieldErrors.email ||
        fieldErrors.username
      ) {
        toast({
          title: 'Registration Failed',
          description: (
            <p>
              An account with this email or username already exists. Please{' '}
              <Link href="/login" className="text-blue-600 hover:text-blue-700 font-medium">
                Sign in
              </Link>
              .
            </p>
          ),
          variant: 'destructive',
          duration: 5000,
        });
      } else {
        toast({
          title: 'Registration Failed',
          description: errorMessage,
          variant: 'destructive',
          duration: 5000,
        });
      }
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type, checked } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value,
    }));
  };

  return (
    <AuthForm
      title="Sign Up"
      subtitle="Create your account to get started"
      onSubmit={handleSubmit}
      isLoading={isLoading}
      submitText="Create Account"
      footer={
        <p className="text-center text-sm text-gray-600 dark:text-gray-400">
          Already have an account?{' '}
          <Link href="/login" className="text-blue-600 hover:text-blue-700 font-medium">
            Sign in
          </Link>
        </p>
      }
    >
      <div className="space-y-4">
        <FormField
          label="First Name" // Changed label
          type="text"
          name="firstName" // Changed name
          value={formData.firstName} // Changed value
          onChange={handleChange}
          required
          placeholder="Enter your first name" // Changed placeholder
        />
        <FormField
          label="Last Name" // Added
          type="text"
          name="lastName" // Added
          value={formData.lastName} // Added
          onChange={handleChange}
          required
          placeholder="Enter your last name" // Added
        />

        <FormField
          label="Email Address"
          type="email"
          name="email"
          value={formData.email}
          onChange={handleChange}
          required
          placeholder="Enter your email"
        />

        <FormField
          label="Username"
          type="text"
          name="username"
          value={formData.username}
          onChange={handleChange}
          required
          placeholder="Create a username"
        />

        <FormField
          label="Password"
          type="password"
          name="password"
          value={formData.password}
          onChange={handleChange}
          required
          placeholder="Create a password"
          helperText="Must be at least 8 characters with uppercase, lowercase, number, and special character"
        />

        <FormField
          label="Confirm Password"
          type="password"
          name="confirmPassword"
          value={formData.confirmPassword}
          onChange={handleChange}
          required
          placeholder="Confirm your password"
        />

        <div className="flex items-start">
          <div className="flex items-center h-5">
            <input
              type="checkbox"
              id="acceptTerms"
              name="acceptTerms"
              checked={formData.acceptTerms}
              onChange={handleChange}
              className="h-4 w-4 text-blue-600 focus:ring-blue-500 border-gray-300 rounded"
            />
          </div>
          <div className="ml-3 text-sm">
            <label htmlFor="acceptTerms" className="text-gray-600 dark:text-gray-300">
              I agree to the{' '}
              <Link href="/terms" className="text-blue-600 hover:text-blue-700 font-medium">
                Terms of Service
              </Link>
              and{' '}
              <Link href="/privacy" className="text-blue-600 hover:text-blue-700 font-medium">
                Privacy Policy
              </Link>
            </label>
          </div>
        </div>
      </div>
    </AuthForm>
  );
}

'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { FaSpinner, FaEnvelope } from 'react-icons/fa';

export default function ResendVerificationPage() {
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');
  const [error, setError] = useState('');
  const router = useRouter();

  const handleResendVerification = async () => {
    setLoading(true);
    setError('');
    setMessage('');

    try {
      const response = await fetch('/api/auth/email/resend', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
      });

      const data = await response.json();

      if (response.ok) {
        setMessage('Verification email sent! Please check your inbox.');
        // Optionally redirect after a delay
        setTimeout(() => {
          router.push('/login');
        }, 3000);
      } else {
        setError(data.message || 'Failed to send verification email');
      }
    } catch (error) {
      setError('An error occurred. Please try again later.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-md w-full space-y-8">
        <div>
          <h2 className="mt-6 text-center text-3xl font-extrabold text-gray-900">
            Resend Verification Email
          </h2>
          <p className="mt-2 text-center text-sm text-gray-600">
            Didn&apos;t receive the verification email? We&apos;ll send it again.
          </p>
        </div>

        <div className="mt-8 space-y-6">
          {message && (
            <div className="rounded-md bg-green-50 p-4">
              <div className="flex">
                <div className="flex-shrink-0">
                  <FaEnvelope className="h-5 w-5 text-green-400" />
                </div>
                <div className="ml-3">
                  <p className="text-sm font-medium text-green-800">{message}</p>
                </div>
              </div>
            </div>
          )}

          {error && (
            <div className="rounded-md bg-red-50 p-4">
              <div className="flex">
                <div className="ml-3">
                  <p className="text-sm font-medium text-red-800">{error}</p>
                </div>
              </div>
            </div>
          )}

          <button
            onClick={handleResendVerification}
            disabled={loading}
            className={`group relative w-full flex justify-center py-2 px-4 border border-transparent text-sm font-medium rounded-md text-white ${
              loading
                ? 'bg-indigo-400 cursor-not-allowed'
                : 'bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500'
            }`}
          >
            {loading ? (
              <>
                <FaSpinner className="animate-spin -ml-1 mr-2 h-5 w-5" />
                Sending...
              </>
            ) : (
              'Resend Verification Email'
            )}
          </button>
        </div>
      </div>
    </div>
  );
}

'use client';

import { Suspense, useEffect, useState } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import Link from 'next/link';
import { FaEnvelope, FaSpinner, FaCheck, FaTimes } from 'react-icons/fa';

function VerifyEmailContent() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const [status, setStatus] = useState<'verifying' | 'success' | 'error'>('verifying');
  const [message, setMessage] = useState('Verifying your email...');

  useEffect(() => {
    const verifyEmail = async () => {
      const token = searchParams?.get('token');
      if (!token) {
        setStatus('error');
        setMessage('Invalid verification link');
        return;
      }

      try {
        const response = await fetch(`/api/auth/verify-email/${token}`, {
          method: 'GET',
        });

        const data = await response.json();

        if (response.ok) {
          setStatus('success');
          setMessage(data.message || 'Email verified successfully!');
          // Redirect to login after 3 seconds
          setTimeout(() => {
            router.push('/login');
          }, 3000);
        } else {
          setStatus('error');
          setMessage(data.message || 'Failed to verify email');
        }
      } catch (error) {
        setStatus('error');
        setMessage('An error occurred while verifying your email');
      }
    };

    verifyEmail();
  }, [router, searchParams]);

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-md w-full space-y-8">
        <div>
          <h2 className="mt-6 text-center text-3xl font-extrabold text-gray-900">
            Email Verification
          </h2>
        </div>

        <div className="mt-8 space-y-6">
          <div className="rounded-md bg-white px-6 py-5 shadow-sm">
            <div className="flex flex-col items-center space-y-4">
              <div className="rounded-full bg-gray-100 p-3">
                {status === 'verifying' && (
                  <FaSpinner className="h-6 w-6 text-blue-500 animate-spin" />
                )}
                {status === 'success' && <FaCheck className="h-6 w-6 text-green-500" />}
                {status === 'error' && <FaTimes className="h-6 w-6 text-red-500" />}
              </div>
              <div className="text-center">
                <p
                  className={`text-lg ${
                    status === 'verifying'
                      ? 'text-blue-600'
                      : status === 'success'
                        ? 'text-green-600'
                        : 'text-red-600'
                  }`}
                >
                  {message}
                </p>
              </div>
              {status === 'error' && (
                <div className="text-center space-y-3">
                  <p className="text-sm text-gray-500">
                    If you're having trouble verifying your email, you can:
                  </p>
                  <button
                    onClick={async () => {
                      try {
                        const response = await fetch('/api/auth/email/resend', {
                          method: 'POST',
                        });
                        const data = await response.json();
                        if (response.ok) {
                          setMessage('New verification email sent! Please check your inbox.');
                        } else {
                          setMessage(data.message || 'Failed to resend verification email');
                        }
                      } catch (error) {
                        setMessage('Failed to resend verification email');
                      }
                    }}
                    className="text-blue-600 hover:text-blue-500"
                  >
                    Request a new verification link
                  </button>
                  <div className="pt-2">
                    <Link href="/login" className="text-blue-600 hover:text-blue-500">
                      Return to login
                    </Link>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default function VerifyEmailPage() {
  return (
    <Suspense
      fallback={
        <div className="min-h-screen flex items-center justify-center bg-gray-50 py-12 px-4 sm:px-6 lg:px-8">
          <div className="max-w-md w-full space-y-8 text-center">
            <FaEnvelope className="mx-auto h-10 w-10 text-blue-500 animate-pulse" />
            <p className="text-lg text-blue-600">Preparing verification details...</p>
          </div>
        </div>
      }
    >
      <VerifyEmailContent />
    </Suspense>
  );
}

