            searchQuery=""
            setSearchQuery={() => {}}
            notifications={[]}
            notificationsOpen={false}
            setNotificationsOpen={() => {}}
            selectedFilter="all"
            setSelectedFilter={() => {}}
            onNotificationRefresh={() => {}}
