/**
 * FSRS Card interface (enhanced for FSRS)
 * Free Spaced Repetition Scheduler algorithm implementation
 * Provides optimized scheduling for flashcard review based on memory science
 */
interface FSRSFlashcard {
  id: string;
  front: string;
  back: string;
  stability: number; // in days
  difficulty: number; // 1-10
  retrievability?: number;
  elapsedDays: number;
  scheduledDays: number;
  reps: number;
  lapses: number;
  state: 'new' | 'learning' | 'review' | 'relearning';
  due: Date;
  isDue: boolean;
  isNew: boolean;
  isLearning: boolean;
  isReview: boolean;
  isRelearning: boolean;
}

// FSRS Algorithm Implementation (based on formulas from borretti.me)
class FSRS {
  private W: number[]; // 19 parameters
  private desiredRetention: number = 0.90;
  private F: number = 19 / 81; // ~0.234
  private C: number = -0.5;

  constructor() {
    // Default W parameters from FSRS (approximate values; in real app, optimize via ML)
    this.W = [
      0.40,  // w0: S0(Forgot)
      0.60,  // w1: S0(Hard)
      0.80,  // w2: S0(Good)
      1.00,  // w3: S0(Easy)
      2.20,  // w4: D0 base
      0.20,  // w5: D0 scale
      0.10,  // w6: delta D scale
      0.34,  // w7: D smoothing
      0.40,  // w8: alpha base
      0.80,  // w9: stability scale
      0.20,  // w10: retrievability scale
      1.00,  // w11: fail base
      0.50,  // w12: fail difficulty
      0.20,  // w13: fail stability
      0.10,  // w14: fail retrievability
      0.80,  // w15: hard multiplier
      1.20,  // w16: easy multiplier
      1.00,  // w17: (unused in basic)
      1.00,  // w18: (unused in basic)
    ];
  }

  // Retrievability R(t, S)
  private retrievability(t: number, S: number): number {
    return Math.pow(1 + this.F * (t / S), this.C);
  }

  // Interval I(R_d, S)
  private interval(Rd: number, S: number): number {
    return (S / this.F) * (Math.pow(Rd, 1 / this.C) - 1);
  }

  // Initial stability S0(G)
  private initialStability(grade: 0 | 1 | 2 | 3 | 4): number {
    const grades = [0, 0.4, 0.6, 0.8, 1.0]; // w0-w3
    return grades[grade] || 0.4;
  }

  // Initial difficulty D0(G)
  private initialDifficulty(grade: 0 | 1 | 2 | 3 | 4): number {
    const raw = this.W[4] - Math.exp(this.W[5] * (grade - 1)) + 1;
    return Math.max(1, Math.min(10, raw));
  }

  // Delta difficulty
  private deltaDifficulty(grade: number): number {
    return -this.W[6] * (grade - 3);
  }

  // Update difficulty
  private updateDifficulty(D: number, grade: number): number {
    let delta = this.deltaDifficulty(grade);
    let Dp = D + delta * ((10 - D) / 9);
    let D0Easy = this.initialDifficulty(4);
    let newD = this.W[7] * D0Easy + (1 - this.W[7]) * Dp;
    return Math.max(1, Math.min(10, newD));
  }

  // Stability on success
  private stabilitySuccess(D: number, S: number, R: number, grade: 2 | 3 | 4): number {
    let td = 11 - D;
    let ts = Math.pow(S, -this.W[9]);
    let tr = Math.exp(this.W[10] * (1 - R)) - 1;
    let h = grade === 2 ? this.W[15] : 1;
    let b = grade === 4 ? this.W[16] : 1;
    let c = Math.exp(this.W[8]);
    let alpha = 1 + td * ts * tr * h * b * c;
    return S * alpha;
  }

  // Stability on failure
  private stabilityFail(D: number, S: number, R: number): number {
    let df = Math.pow(D, -this.W[12]);
    let sf = Math.pow(S + 1, this.W[13]) - 1;
    let rf = Math.exp(this.W[14] * (1 - R));
    let Sf = df * sf * rf * this.W[11];
    return Math.min(Sf, S);
  }

  // Update stability
  private updateStability(D: number, S: number, R: number, grade: number): number {
    if (grade < 3) {
      return this.stabilityFail(D, S, R);
    } else {
      return this.stabilitySuccess(D, S, R, grade as 2 | 3 | 4);
    }
  }

  // Schedule next review for new card
  public scheduleNew(grade: 0 | 1 | 2 | 3 | 4): { stability: number; difficulty: number; scheduledDays: number } {
    const S0 = this.initialStability(grade);
    const D0 = this.initialDifficulty(grade);
    const I = Math.max(1, Math.round(this.interval(this.desiredRetention, S0)));
    return { stability: S0, difficulty: D0, scheduledDays: I };
  }

  // Update existing card
  public updateCard(card: FSRSFlashcard, grade: 0 | 1 | 2 | 3 | 4): FSRSFlashcard {
    let S = card.stability;
    let D = card.difficulty;
    let t = card.elapsedDays; // time since last review

    let R = this.retrievability(t, S);

    let newS = this.updateStability(D, S, R, grade);

    let newD = this.updateDifficulty(D, grade);

    let newI = Math.max(1, Math.round(this.interval(this.desiredRetention, newS)));

    // Update reps, lapses, etc.
    let newReps = card.reps + 1;
    let newLapses = grade < 3 ? card.lapses + 1 : card.lapses;

    // Determine new state
    let newState: FSRSFlashcard['state'] = 'review';
    if (grade < 3) newState = 'relearning';
    else if (card.state === 'new') newState = 'learning';

    const now = new Date();
    const newDue = new Date(now.getTime() + newI * 86400000);

    return {
      ...card,
      stability: newS,
      difficulty: newD,
      retrievability: this.desiredRetention,
      elapsedDays: 0,
      scheduledDays: newI,
      reps: newReps,
      lapses: newLapses,
      state: newState,
      due: newDue,
      isDue: false,
      isNew: false,
      isLearning: newState === 'learning',
      isReview: newState === 'review',
      isRelearning: newState === 'relearning',
    };
  }
}

