  const searchTimeoutRef = useRef<number | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);
  const SEARCH_TIMEOUT = 5000; // 5 seconds

  // Handle click outside notifications menu
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      const target = event.target as Node;
      if (
        notificationsMenuRef.current &&
        notificationsButtonRef.current &&
        !notificationsMenuRef.current.contains(target) &&
        !notificationsButtonRef.current.contains(target)
      ) {
        setNotificationsOpen(false);
      }
    };

    if (notificationsOpen) {
      document.addEventListener('mousedown', handleClickOutside);
      return () => {
        document.removeEventListener('mousedown', handleClickOutside);
      };
    }
  }, [notificationsOpen, setNotificationsOpen]);

  // Handle click outside user menu
  useEffect(() => {
    const handleClickOutsideUser = (event: MouseEvent) => {
      const target = event.target as Node;
      if (
        userMenuRef.current &&
        userMenuButtonRef.current &&
        !userMenuRef.current.contains(target) &&
        !userMenuButtonRef.current.contains(target)
      ) {
        setUserMenuOpen(false);
      }
    };

    if (userMenuOpen) {
      document.addEventListener('mousedown', handleClickOutsideUser);
      return () => document.removeEventListener('mousedown', handleClickOutsideUser);
    }
  }, [userMenuOpen, setUserMenuOpen]);

  // Sync external searchQuery prop into localQuery when it changes externally
  useEffect(() => {
    setLocalQuery(searchQuery || '');
  }, [searchQuery]);

  const doSearch = useCallback(async (q: string, filter?: string) => {
    // cancel previous
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }
    if (searchTimeoutRef.current) {
      window.clearTimeout(searchTimeoutRef.current);
    }
    if (!q || q.trim().length === 0) {
      setSearchResults([]);
      setIsSearching(false);
      setSearchError(null);
      return;
    }

    setIsSearching(true);
    setSearchError(null);
    const ctrl = new AbortController();
    abortControllerRef.current = ctrl;

    // Set timeout to abort search after 5 seconds
    searchTimeoutRef.current = window.setTimeout(() => {
      ctrl.abort();
    }, SEARCH_TIMEOUT);

    try {
      const params = new URLSearchParams();
      params.set('search', q);
      if (filter) params.set('filter', filter);
      params.set('limit', '6');

      const res = await fetch(`/api/courses?${params.toString()}`, { signal: ctrl.signal });
      if (!res.ok) throw new Error(`Search failed: ${res.statusText}`);
      const data = await res.json();
      // assume data is array of courses or { data: [...] }
      const results = Array.isArray(data) ? data : data?.data || [];
      setSearchResults(results.slice(0, 6));
      setSearchError(null);
    } catch (err) {
      if ((err as any).name === 'AbortError') {
        setSearchError('Search request timed out. Please try again.');
      } else {
        console.error('Search error', err);
        setSearchError('Failed to search. Please try again.');
      }
      setSearchResults([]);
    } finally {
      setIsSearching(false);
      if (searchTimeoutRef.current) {
        window.clearTimeout(searchTimeoutRef.current);
      }
    }
  }, [SEARCH_TIMEOUT]);

  // Debounced handler
  const handleSearchChange = (q: string) => {
    setLocalQuery(q);
    setSearchQuery(q);

    if (searchTimeout.current) {
      window.clearTimeout(searchTimeout.current);
    }
    // debounce 300ms
    searchTimeout.current = window.setTimeout(() => {
      doSearch(q, selectedFilter);
    }, 300);
  };

  useEffect(() => {
    return () => {
      if (searchTimeout.current) window.clearTimeout(searchTimeout.current);
      if (searchTimeoutRef.current) window.clearTimeout(searchTimeoutRef.current);
      if (abortControllerRef.current) abortControllerRef.current.abort();
    };
  }, []);

  return (
    <header className="sticky top-0 z-50 bg-white border-b border-gray-200 dark:bg-gray-800 dark:border-gray-700 shadow-sm"> {/* Header z-50 */}
      <div className="px-3 sm:px-4 md:px-6 lg:px-8 py-3 sm:py-4 transition-all duration-300"> {/* Adjusted py for better spacing */}
        <div className="flex items-center justify-between gap-4">
          {/* Left side - Welcome/Page Header */}
          <div className="flex items-center gap-3 flex-1 min-w-0">
            {/* Mobile hamburger to open sidebar */}
            <button
              type="button"
              onClick={() => setSidebarOpen(!sidebarOpen)}
              className="lg:hidden p-2 rounded-md hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors mr-1"
              aria-label="Toggle sidebar"
            >
              <Menu className="h-6 w-6 text-gray-700 dark:text-gray-200" />
            </button>

            {header ? (
              <div className="flex items-center gap-3">
                {header.icon && <div className="text-2xl">{header.icon}</div>}
                <div>
                  <h1 className="text-2xl font-bold text-gray-900 dark:text-white truncate">
                    {header.title}
                  </h1>
                  {header.description && (
                    <p className="text-sm text-gray-600 dark:text-gray-400">
                      {header.description}
                    </p>
                  )}
                </div>
              </div>
            ) : (
              <div className="hidden sm:block">
                <h1 className="text-lg font-bold text-gray-900 dark:text-white truncate">
                  Welcome back, {user?.firstName}! 👋
                </h1>
                <p className="text-xs text-gray-600 dark:text-gray-400">Track your progress</p>
              </div>
            )}

            {/* Streak Badge - Hidden on mobile; uses RQ data */}
            {streak > 0 && !progressLoading && (
              <div className="hidden lg:flex items-center gap-1.5 px-2.5 py-1 bg-green-50 dark:bg-green-900/20 rounded-lg border border-green-200 dark:border-green-800 shrink-0">
                <Flame className="w-3.5 h-3.5 text-green-600 dark:text-green-400" />
                <span className="text-xs font-bold text-green-700 dark:text-green-300">
                  {streak}d
                </span>
              </div>
            )}
            {/* Loading placeholder for streak */}
            {progressLoading && (
              <div className="hidden lg:block animate-pulse bg-gray-200 dark:bg-gray-700 w-16 h-6 rounded-full shrink-0" />
            )}
          </div>

          {/* Center - Search and Filter (Desktop only) */}
          <div className="hidden sm:flex gap-2 items-center shrink-0">
            <div className="relative max-w-xs">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
              <input
                type="text"
                placeholder="Search courses..."
                value={localQuery}
                onChange={e => handleSearchChange(e.target.value)}
                aria-label="Search courses"
                className="pl-10 pr-4 py-2 rounded-lg border border-gray-300 bg-white text-gray-900 placeholder-gray-400 focus:border-blue-500 focus:ring-2 focus:ring-blue-200 dark:bg-gray-700 dark:border-gray-600 dark:text-white text-sm"
              />

              {/* Results dropdown (z-50) */}
              {searchResults.length > 0 && (
                <div className="absolute left-0 right-0 mt-2 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-md shadow-lg z-50">
                  <ul className="max-h-64 overflow-y-auto">
                    {searchResults.map((course: any) => (
                      <SearchResultItem
                        key={course.id}
                        course={course}
                        onSelect={() => setSearchResults([])}
                      />
                    ))}
                  </ul>
                </div>
              )}
              {searchError && (
                <div className="absolute right-2 top-1/2 transform -translate-y-1/2 text-xs text-red-500 font-medium">
                  {searchError}
                </div>
              )}
              {isSearching && !searchError && (
                <div className="absolute right-2 top-1/2 transform -translate-y-1/2 text-xs text-gray-500">
                  Searching…
                </div>
              )}
            </div>
            <select
              value={selectedFilter}
              onChange={e => setSelectedFilter(e.target.value)}
              title="Filter courses"
              className="border border-gray-300 rounded-lg px-3 py-2 bg-white text-gray-900 focus:ring-2 focus:ring-blue-500 dark:bg-gray-700 dark:border-gray-600 dark:text-white text-sm"
