'use client';

import { ReactNode, useEffect } from 'react';
import { useSession } from 'next-auth/react';
import AppErrorBoundary from '@/features/security/components/AppErrorBoundary';
import { useAuthStore } from '@/features/auth/store/useAuthStore';

interface LayoutContentProps {
  children: ReactNode;
}

export default function LayoutContent({ children }: LayoutContentProps) {
  const { data: session, status } = useSession();

  // Sync NextAuth session into the Zustand auth store so existing consumers
  // that use `useAuthStore` remain consistent with NextAuth's session state.
  useEffect(() => {
    if (status === 'loading') return;

    if (session?.user) {
      useAuthStore.setState({ user: session.user as any, isAuthenticated: true });
    } else {
      useAuthStore.setState({ user: null, isAuthenticated: false });
    }
  }, [session, status]);

  return (
    <AppErrorBoundary>
      <div className="min-h-screen bg-background">{children}</div>
    </AppErrorBoundary>
  );
}

