// Lightweight service wrapper for dashboard-related API endpoints
export async function getUserProgress(userId: string) {
  return apiClient(`/user-progress/${userId}`);
}

export async function getDeadlines() {
  return apiClient(`/learning-goals?status=upcoming`);
}

export async function getStudyEvents(userId?: string) {
  const url = userId ? `/study-events?userId=${userId}` : '/study-events';
  return apiClient(url);
}

export async function getBadges(userId?: string) {
  const url = userId ? `/badges?userId=${userId}` : '/badges';
  return apiClient(url);
}

export async function getSystemAnalytics() {
  return apiClient('/analytics/system/metrics');
}

export async function getCPDActivities(userId?: string) {
  const url = userId ? `/cpd/activities?userId=${userId}` : `/cpd/activities`;
  try {
    return await apiClient(url);
  } catch (error: any) {
    // The original function had special 404 handling, so we replicate it.
    // This assumes the apiClient might throw an error with a status property.
    // A better apiClient would expose the status code in the thrown error.
    // For now, we'll check the error message.
    if (error.message.includes('404') || error.message.includes('Not Found')) {
      console.warn(`CPD Activities endpoint not found, returning empty array.`);
      return [];
    }
    throw error;
  }
}

import { openDB, DBSchema, IDBPDatabase } from 'idb';

export interface QuizQuestion {
  id: string;
  topic: string;
  question: string;
  options: string[];
  correctAnswer: string;
  explanation: string;
  lastUpdated: number;
}

export interface ReadingMaterial {
  id: string;
  title: string;
  content: Blob;
  metadata: {
    author?: string;
    date?: string;
    topic?: string;
  };
  lastUpdated: number;
}

export interface SyncQueueItem {
  id: string;
  type: 'quiz_submission' | 'progress_log';
  data: any;
  timestamp: number;
  attempts: number;
}

interface MedicalEducationDB extends DBSchema {
  quizQuestions: {
    key: string;
    value: QuizQuestion;
    indexes: { 'by-topic': string };
  };
  readingMaterials: {
    key: string;
    value: ReadingMaterial;
    indexes: { 'by-topic': string };
  };
  syncQueue: {
    key: string;
    value: SyncQueueItem;
    indexes: { 'by-timestamp': number };
  };
}

const DB_NAME = 'medical-education-db';
const DB_VERSION = 1;

export async function initDB(): Promise<IDBPDatabase<MedicalEducationDB>> {
  return openDB<MedicalEducationDB>(DB_NAME, DB_VERSION, {
    upgrade(db) {
      // Quiz Questions store
      const quizStore = db.createObjectStore('quizQuestions', { keyPath: 'id' });
      quizStore.createIndex('by-topic', 'topic');

      // Reading Materials store
      const readingStore = db.createObjectStore('readingMaterials', { keyPath: 'id' });
      readingStore.createIndex('by-topic', 'metadata.topic');

      // Sync Queue store
      const syncStore = db.createObjectStore('syncQueue', { keyPath: 'id' });
      syncStore.createIndex('by-timestamp', 'timestamp');
    },
  });
}

import { offlineService } from './offlineService';

class SyncManager {
  private isOnline: boolean = navigator.onLine;
  private syncInProgress: boolean = false;
  private maxRetries: number = 3;

  constructor() {
    this.setupNetworkListeners();
  }

  private setupNetworkListeners() {
    window.addEventListener('online', this.handleOnline);
    window.addEventListener('offline', this.handleOffline);
  }

  private handleOnline = async () => {
    this.isOnline = true;
    await this.syncPendingItems();
  };

  private handleOffline = () => {
    this.isOnline = false;
  };

  async syncPendingItems() {
    if (this.syncInProgress || !this.isOnline) return;

    try {
      this.syncInProgress = true;
      const items = await offlineService.getSyncQueueItems();

      for (const item of items) {
        if (item.attempts >= this.maxRetries) {
          // Remove items that have exceeded max retries
          await offlineService.removeFromSyncQueue(item.id);
          continue;
        }

        try {
          await this.processSyncItem(item);
          await offlineService.removeFromSyncQueue(item.id);
        } catch (error) {
          console.error(`Failed to sync item ${item.id}:`, error);
          await offlineService.incrementSyncAttempt(item.id);
        }
      }
    } finally {
      this.syncInProgress = false;
    }
  }

  private async processSyncItem(item: any) {
    switch (item.type) {
      case 'quiz_submission':
        await this.syncQuizSubmission(item.data);
        break;
      case 'progress_log':
        await this.syncProgressLog(item.data);
        break;
      default:
        throw new Error(`Unknown sync item type: ${item.type}`);
    }
  }

  private async syncQuizSubmission(data: any) {
    // TODO: Implement actual API call to sync quiz submission
    const response = await fetch('/api/quizzes/submit', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        ...data,
        syncedAt: new Date().toISOString(),
      }),
    });

    if (!response.ok) {
      throw new Error('Failed to sync quiz submission');
    }
  }

  private async syncProgressLog(data: any) {
    // TODO: Implement actual API call to sync progress log
    const response = await fetch('/api/progress/log', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        ...data,
        syncedAt: new Date().toISOString(),
      }),
    });

    if (!response.ok) {
      throw new Error('Failed to sync progress log');
    }
  }

  // Public methods
  async queueQuizSubmission(quizData: any) {
    await offlineService.addToSyncQueue({
      type: 'quiz_submission',
      data: quizData,
      timestamp: Date.now(),
    });

    if (this.isOnline) {
      await this.syncPendingItems();
    }
  }

  async queueProgressLog(progressData: any) {
    await offlineService.addToSyncQueue({
      type: 'progress_log',
      data: progressData,
      timestamp: Date.now(),
    });

    if (this.isOnline) {
      await this.syncPendingItems();
    }
  }

  isCurrentlyOnline() {
    return this.isOnline;
  }
}

