                </Button>
                <Button
                  className="flex-1 bg-green-600 hover:bg-green-700 text-white"
                  onClick={() => handleAnswerSelect('correct', true)}
                  size="lg"
                >
                  <CheckCircle className="h-4 w-4 mr-2" />I got it right
