export const useQuizToFlashcard = () => {
  const { user } = useAuthStore();

  const convertQuizToFlashcards = async (questions: QuizQuestion[]) => {
    if (!user) return;
    await QuizToFlashcardService.convertQuizToFlashcards(questions, user.id);
