'use client';

import { signOut, useSession } from 'next-auth/react';
import { Button } from '@/shared/components/ui/button';
import { Card } from '@/shared/components/ui/card';
import { useToast } from '@/shared/components/ui/use-toast';

export function SessionManager() {
  const { data: session, status } = useSession();
  const { toast } = useToast();
  const loading = status === 'loading';

  const handleTerminateSession = async () => {
    try {
      await signOut({ callbackUrl: '/login' });
      toast({
        title: 'Signed Out',
        description: 'You have been successfully signed out.',
      });
    } catch (error) {
      toast({
        variant: 'destructive',
        title: 'Sign Out Failed',
        description: 'An error occurred while signing out. Please try again.',
      });
    }
  };

  if (loading) {
    return <div className="flex justify-center py-8">Loading session...</div>;
  }

  if (!session) {
    return null;
  }

  const userName =
    session.user?.firstName || session.user?.lastName
      ? `${session.user.firstName || ''} ${session.user.lastName || ''}`.trim()
      : session.user?.username || 'Current Session';

  return (
    <div className="space-y-4">
      <Card className="p-4">
        <div className="flex items-center justify-between">
          <div>
            <h3 className="font-medium">{userName}</h3>
            <p className="text-sm text-muted-foreground">
              Email: {session.user?.email || 'Not available'}
            </p>
            <p className="text-sm text-muted-foreground">
              Session expires: {new Date(session.expires).toLocaleString()}
            </p>
          </div>
          <Button variant="destructive" size="sm" onClick={handleTerminateSession}>
            Sign Out
          </Button>
        </div>
      </Card>
    </div>
  );
}

