      // Verify session was established
      const session = await getSession();
      if (!session?.accessToken) {
        console.error('Session not established after login');
        throw new Error('Failed to establish session');
      }

      console.log('Login successful, session established');
      return response.data;
    } catch (error) {
      console.error('Login error:', error);
      if (error instanceof AxiosError) {
        throw new Error(error.response?.data?.message || 'Login failed');
      }
      throw error;
    }
  }

  async register(registerData: RegisterDTO): Promise<RegisterResponse> {
    // Use apiService for registration, as it's an unauthenticated endpoint initially
    const response = await apiService.post<RegisterResponse>('/auth/register', registerData);
    return response.data;
  }

  async logout(): Promise<void> {
    try {
      // Clear auth store state immediately
      useAuthStore.getState().clearUser();

      // Use NextAuth's signOut which handles the backend logout via the signout callback
      await signOut({
        redirect: true,
        callbackUrl: '/login',
      });
    } catch (error) {
      console.error('Logout error:', error);
      // Still attempt to sign out even if there's an error
      try {
        await signOut({
          redirect: true,
          callbackUrl: '/login',
        });
      } catch (e) {
        console.error('Final logout attempt failed:', e);
        // Force redirect to login as fallback
        window.location.href = '/login';
      }
