  /**
   * Check if user has a specific role or any of the required roles.
   * Checks against all user roles (stored in user.roles array)
   * @param requiredRoles - A single role string or array of role strings to check
   * @returns true if user has any of the required roles, false otherwise
   */
  hasRole(requiredRoles: string | string[]): boolean {
    const session = getSession().then(s => s);
    // Note: This is synchronous but getSession is async, so we need to handle this differently
    // For now, we'll use the authStore as a fallback
    const user = useAuthStore.getState().user;
    if (!user) return false;

    const rolesArray = Array.isArray(requiredRoles) ? requiredRoles : [requiredRoles];
    const userRoles = (user as any).roles || [user.role]; // Use all roles if available

    return rolesArray.some(role => userRoles.includes(role));
  }

