};

import { NextAuthOptions } from 'next-auth';
import CredentialsProvider from 'next-auth/providers/credentials';
import GoogleProvider from 'next-auth/providers/google';
import GithubProvider from 'next-auth/providers/github';
import { User, AuthResponse } from '@/shared/types/authInterface'; // Rename User to avoid conflict
import { Role } from '@/shared/enums/role.enum'; // Import Role as a value
import { JWT } from 'next-auth/jwt';
import { AuthError, AuthErrorCode, AUTH_ERROR_MESSAGES } from './authErrors';

// This function will handle token refreshing
async function refreshAccessToken(token: JWT): Promise<JWT> {
  try {
    // Ensure we have a refresh token before attempting refresh
    if (!token.refreshToken) {
      console.warn('Token refresh attempted but no refresh token available');
      return {
        ...token,
        error: 'RefreshAccessTokenError',
      };
    }

    const raw =
      process.env.NEXT_PUBLIC_API_URL || process.env.BACKEND_URL || 'http://localhost:3002';
    const response = await fetch(`${raw}/auth/refresh`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        userId: token.id,
        refreshToken: token.refreshToken,
      }),
    });

    const data = await response.json();

    if (!response.ok) {
      console.error('Token refresh failed from backend:', data.message || 'Unknown error');
      throw new Error(data.message || 'Failed to refresh token');
    }

    const refreshedTokens = data.data;

    // Keep the existing refresh token if a new one wasn't provided
    const newRefreshToken = refreshedTokens.refreshToken || token.refreshToken;

    console.log('Token refresh successful:', {
      accessToken: refreshedTokens.accessToken ? 'present' : 'missing',
      expiresAt: refreshedTokens.expiresAt,
      refreshToken: newRefreshToken ? 'present' : 'missing',
    });

    // Update the token with new values from the refresh endpoint
    return {
      ...token,
      accessToken: refreshedTokens.accessToken,
      accessTokenExpires: new Date(refreshedTokens.expiresAt).getTime(),
      refreshToken: newRefreshToken,
      error: undefined, // Clear any previous errors
    };
  } catch (error) {
    console.error('Error refreshing access token:', error);

    // Mark the token with refresh error
    return {
      ...token,
      error: 'RefreshAccessTokenError',
    };
  }
}

export const authOptions: NextAuthOptions = {
  debug: process.env.NODE_ENV === 'development',
  providers: [
    // Credentials Provider
    CredentialsProvider({
      name: 'Credentials',
      credentials: {
        identifier: { label: 'Email or Username', type: 'text' },
        password: { label: 'Password', type: 'password' },
      },
      async authorize(credentials, req) {
        // Skip token refresh via authorize - this is handled in the JWT callback
        if (credentials?.identifier === 'refresh') {
          console.warn(
            'Refresh credentials should not be handled via authorize callback. This will be ignored.'
          );
          return null;
        }

        console.log(
          'Authorize function called with credentials:',
          credentials ? { identifier: credentials.identifier } : credentials
        );

        if (!credentials?.identifier || !credentials?.password) {
          console.error('Missing credentials');
          return null;
        }

        // Prefer explicit BACKEND_URL, fall back to public envs, then default
        const raw =
          process.env.BACKEND_URL ||
          process.env.NEXT_PUBLIC_API_BASE_URL ||
          process.env.NEXT_PUBLIC_API_URL ||
          'http://localhost:3002';
        const loginUrl = new URL('/v1/auth/login', raw).href;

        console.log('Calling backend to authenticate at', loginUrl);

        const loginBody = {
          password: credentials.password,
          ...(String(credentials.identifier).includes('@')
            ? { email: credentials.identifier }
            : { username: credentials.identifier }),
        };

        // timeout for fetch
        const timeoutMs = 7000;
        const controller = new AbortController();
        const timeout = setTimeout(() => controller.abort(), timeoutMs);

        try {
          // log outgoing payload for debugging
          console.log('Authorize: sending loginBody to backend:', loginBody);

          const response = await fetch(loginUrl, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', Accept: 'application/json' },
            body: JSON.stringify(loginBody),
            signal: controller.signal,
          });

          clearTimeout(timeout);

          const text = await response.text();
          // log raw text to help diagnose non-JSON errors
          console.log('Authorize: raw backend response text:', text);

          let responseData: any = {};
          try {
            responseData = text ? JSON.parse(text) : {};
          } catch (parseErr) {
            // keep raw text if not JSON
            responseData = { raw: text };
          }

          console.log('Backend response status:', response.status);
          console.log('Backend response data:', responseData);

          if (!response.ok) {
            console.error('Backend authentication failed:', response.status, responseData);

            let errorMessage = responseData.message || 'Authentication failed';
            let errorCode: AuthErrorCode = AuthErrorCode.INVALID_CREDENTIALS;

            switch (responseData.message) {
              case AUTH_ERROR_MESSAGES[AuthErrorCode.INVALID_CREDENTIALS]:
                errorCode = AuthErrorCode.INVALID_CREDENTIALS;
                break;
              case AUTH_ERROR_MESSAGES[AuthErrorCode.ACCOUNT_LOCKED]:
                errorCode = AuthErrorCode.ACCOUNT_LOCKED;
                break;
              case AUTH_ERROR_MESSAGES[AuthErrorCode.EMAIL_NOT_VERIFIED]:
                errorCode = AuthErrorCode.EMAIL_NOT_VERIFIED;
                break;
              case AUTH_ERROR_MESSAGES[AuthErrorCode.TOKEN_EXPIRED]:
                errorCode = AuthErrorCode.TOKEN_EXPIRED;
                break;
              case AUTH_ERROR_MESSAGES[AuthErrorCode.INVALID_TOKEN]:
                errorCode = AuthErrorCode.INVALID_TOKEN;
                break;
              case AUTH_ERROR_MESSAGES[AuthErrorCode.INSUFFICIENT_PERMISSIONS]:
                errorCode = AuthErrorCode.INSUFFICIENT_PERMISSIONS;
                break;
              case AUTH_ERROR_MESSAGES[AuthErrorCode.RATE_LIMIT_EXCEEDED]:
                errorCode = AuthErrorCode.RATE_LIMIT_EXCEEDED;
                break;
              case AUTH_ERROR_MESSAGES[AuthErrorCode.MFA_REQUIRED]:
                errorCode = AuthErrorCode.MFA_REQUIRED;
                break;
              case AUTH_ERROR_MESSAGES[AuthErrorCode.INVALID_MFA_CODE]:
                errorCode = AuthErrorCode.INVALID_MFA_CODE;
                break;
              case AUTH_ERROR_MESSAGES[AuthErrorCode.SESSION_EXPIRED]:
                errorCode = AuthErrorCode.SESSION_EXPIRED;
                break;
              case AUTH_ERROR_MESSAGES[AuthErrorCode.CSRF_TOKEN_INVALID]:
                errorCode = AuthErrorCode.CSRF_TOKEN_INVALID;
                break;
              case AUTH_ERROR_MESSAGES[AuthErrorCode.PASSWORD_CONFIRMATION_REQUIRED]:
                errorCode = AuthErrorCode.PASSWORD_CONFIRMATION_REQUIRED;
                break;
              default:
                // For any other unexpected errors from backend
                errorCode = AuthErrorCode.INVALID_CREDENTIALS;
                break;
            }

            throw new AuthError(errorMessage, errorCode, response.status);
          }

          const user = responseData?.data?.user;
          const access_token = responseData?.data?.accessToken;
          const refresh_token = responseData?.data?.refreshToken;
          const expires_at = responseData?.data?.expiresAt; // Extract expires_at

          if (!user) {
            console.error('Unexpected backend response shape for login:', responseData);
            throw new Error('Authentication failed: Invalid user data received from backend.');
          }

          const userObj: User = {
            id: user.id,
            email: user.email,
            firstName: user.firstName,
            lastName: user.lastName,
            username: user.username,
            role: user.role,
            roles: user.roles || [user.role], // Include all user roles from backend
            isEmailVerified: user.isEmailVerified,
            permissions: user.permissions || [], // Ensure permissions is always an array
            accessToken: access_token,
            refreshToken: refresh_token, // Store the refresh token
            accessTokenExpires: new Date(expires_at).getTime(), // Set accessTokenExpires
          };

          console.info('Authorize success for', user.email ?? user.id);
          return userObj;
        } catch (err: any) {
          clearTimeout(timeout);
          if (err?.name === 'AbortError') {
            console.error('Authorize error: request to backend timed out after', timeoutMs, 'ms');
          } else {
            console.error('Authorize error calling backend:', err);
          }
          throw new Error(err.message || 'An unexpected error occurred during authentication.');
        }
      },
    }),

    // Google Provider
    GoogleProvider({
      clientId: process.env.GOOGLE_CLIENT_ID || '',
      clientSecret: process.env.GOOGLE_CLIENT_SECRET || '',
      authorization: {
        params: {
          prompt: 'consent',
          access_type: 'offline',
          response_type: 'code',
        },
      },
    }),

    // GitHub Provider
    GithubProvider({
      clientId: process.env.GITHUB_ID || '',
      clientSecret: process.env.GITHUB_SECRET || '',
    }),
  ],

  callbacks: {
    async jwt({ token, user, account }): Promise<JWT> {
      // Type assertion for token to allow custom properties
      const customToken = token as any;
      if (account && user) {
        console.log('JWT Callback: Initial sign in');
        return {
          ...token,
          id: user.id,
          role: user.role as Role,
          roles: (user as any).roles || [user.role as Role], // Store all user roles
          accessToken: user.accessToken || '',
          permissions: user.permissions || [],
          accessTokenExpires: user.accessTokenExpires || Date.now() + 24 * 60 * 60 * 1000,
          refreshToken: user.refreshToken ?? '',
          firstName: (user as any).firstName,
          lastName: (user as any).lastName,
          error: undefined,
        };
      }

      // If no access token expiration is set, return token as-is
      if (!token.accessTokenExpires) {
        console.warn('Token missing accessTokenExpires, cannot determine if refresh needed');
        return token;
      }

      // Return previous token if the access token has not expired yet
      // Refresh 5 minutes before expiry to avoid edge cases
      const refreshBuffer = 5 * 60 * 1000; // 5 minutes
      if (Date.now() < (token.accessTokenExpires as number) - refreshBuffer) {
        console.log('Token still valid, no refresh needed');
        return token;
      }

      console.log('Token expired or about to expire, attempting refresh...');

      // If token has expired or is about to expire, try to refresh it
      if (token.refreshToken) {
        const refreshedToken = await refreshAccessToken(token);

        // If refresh succeeded (no error), return the new token
        if (!refreshedToken.error) {
          console.log('Token refresh completed successfully');
          return refreshedToken;
        }

        console.warn('Token refresh failed, but checking if current token still valid...');

        // If refresh failed but we still have a valid access token, keep using it
        if (
          token.accessToken &&
          token.accessTokenExpires &&
          Date.now() < (token.accessTokenExpires as number)
        ) {
          console.log('Token refresh failed but current token still valid, continuing session');
          return token;
        }
      }

      console.error('Token refresh failed and no valid token available, marking as error');
      // If we get here, both refresh and current token are invalid
      return {
        ...token,
        error: 'TokenExpiredError',
      } as unknown as JWT;
    },

    async session({ session, token }) {
      // Cast token to access our custom properties
      const customToken = token as any;

      // If token has a refresh error, log it and mark session as having error
      // The client/middleware will handle re-authentication and redirect
      if (customToken.error === 'TokenExpiredError') {
        console.warn('Session token expired, user should be redirected to marketing page');
      } else if (customToken.error === 'RefreshAccessTokenError') {
        console.warn('Session has refresh error, client should handle re-authentication');
      }

      // Send properties to the client, such as an access_token from a provider.
      session.accessToken = (customToken.accessToken as string) || '';
      session.accessTokenExpires = (customToken.accessTokenExpires as number) || Date.now();
      session.refreshToken = (customToken.refreshToken as string) || '';
      session.error = (customToken.error as string) || undefined;
      session.user.id = (customToken.id as string) || '';
      session.user.role = (customToken.role as Role) || Role.guest;
      session.user.roles = ((customToken.roles as Role[]) || [customToken.role as Role]) as Role[];
      session.user.permissions = (customToken.permissions as string[]) || [];
      session.user.firstName = (customToken.firstName as string) || '';
      session.user.lastName = (customToken.lastName as string) || '';
      return session;
    },

    async redirect({ url, baseUrl }) {
      // Always redirect to the dashboard after sign-in if authenticated.
      // The middleware will handle further redirects based on user role or other factors.
      return new URL('/dashboard', baseUrl).toString();
    },
  },

  pages: {
    signIn: '/login',
    error: '/auth/error',
  },

  session: {
    strategy: 'jwt',
    maxAge: 30 * 24 * 60 * 60, // 30 days
    updateAge: 24 * 60 * 60, // 24 hours - how frequently to extend session
  },

  jwt: {
    maxAge: 30 * 24 * 60 * 60, // 30 days - matches session maxAge
  },

  cookies: {
    sessionToken: {
      name: 'next-auth.session-token',
      options: {
        httpOnly: true,
        sameSite: 'lax',
        path: '/',
        secure: process.env.NODE_ENV === 'production',
      },
    },
  },
};

