'use client';

import React, { useState, useEffect } from 'react';
import {
  BookOpen,
  Clock,
  Users,
  Star,
  TrendingUp,
  Sparkles,
  ArrowRight,
  CheckCircle,
  AlertCircle,
  Filter,
  Search,
  Grid3x3,
  Award,
  BarChart3,
  X,
} from 'lucide-react';
import { useQuery } from '@tanstack/react-query';
import { usePageHeader } from '@/core/providers/HeaderContext';
import { apiService } from '@/features/auth/services/apiClient';
import { toast } from 'sonner';
import type { Course } from '@/features/courses/types/courseInterfaces';

/**
 * Course Statistics Interface
 * Represents aggregate statistics ABOUT user's course enrollment (platform-wide)
 * Changed from CourseStats to CourseStatistics for consistency with backend
 * 
 * This is NOT individual course progress - see CourseProgress interface for that.
 * This represents USER-LEVEL statistics derived from all course progress.
 */
interface CourseStatistics {
  totalEnrolled: number;      // Total courses user is enrolled in
  completed: number;           // Total courses user completed
  inProgress: number;          // Total courses currently in progress
  avgScore: number;            // Average score across all courses
  hoursSpent: number;          // Total hours spent across all courses
  streak: number;              // Current learning streak
}

interface CourseFilter {
  searchTerm: string;
  difficulty: string;
  category: string;
  status: 'all' | 'enrolled' | 'completed' | 'recommended';
}

export const CoursesDashboard = () => {
  const { setHeader } = usePageHeader();
  const [filters, setFilters] = useState<CourseFilter>({
    searchTerm: '',
    difficulty: '',
    category: '',
    status: 'all',
  });
  const [showAnalytics, setShowAnalytics] = useState(false);
  const [selectedCourse, setSelectedCourse] = useState<Course | null>(null);

  // Set page header
  useEffect(() => {
    setHeader({
      title: 'Courses',
      description: 'Explore and enroll in medical education courses',
      icon: '📚',
    });

    return () => {
      setHeader(null);
    };
  }, [setHeader]);

  // Fetch all courses with filters
  const { data: coursesData = { courses: [], stats: {} }, isLoading: coursesLoading } = useQuery({
    queryKey: ['courses', filters],
    queryFn: async () => {
      try {
        const params = new URLSearchParams();
        if (filters.searchTerm) params.append('search', filters.searchTerm);
        if (filters.difficulty) params.append('difficulty', filters.difficulty);
        if (filters.category) params.append('category', filters.category);
        if (filters.status !== 'all') params.append('status', filters.status);

        const response = await apiClient(`/api/courses?${params.toString()}`);
        
        // Handle various response formats
        if (Array.isArray(response)) {
          return { courses: response, stats: {} };
        } else if (response?.data && Array.isArray(response.data)) {
          return { courses: response.data, stats: response.stats || {} };
        } else if (response?.courses && Array.isArray(response.courses)) {
          return { courses: response.courses, stats: response.stats || {} };
        }
        
        return { courses: [], stats: {} };
      } catch (error) {
        console.error('Failed to fetch courses:', error);
        toast.error('Failed to load courses');
        return { courses: [], stats: {} };
      }
    },
    staleTime: 5 * 60 * 1000,
    gcTime: 10 * 60 * 1000,
  });

  // Fetch course statistics
  // TODO: Consider updating endpoint from /api/courses/stats to /api/users/me/course-statistics
  const { data: courseStatistics = { totalEnrolled: 0, completed: 0, inProgress: 0, avgScore: 0, hoursSpent: 0, streak: 0 } } = useQuery({
    queryKey: ['courseStatistics'],
    queryFn: async () => {
      try {
        const response = await apiClient('/api/courses/stats');
        if (response?.data) return response.data;
        return response || { totalEnrolled: 0, completed: 0, inProgress: 0, avgScore: 0, hoursSpent: 0, streak: 0 };
      } catch (error) {
        console.error('Failed to fetch course statistics:', error);
        return { totalEnrolled: 0, completed: 0, inProgress: 0, avgScore: 0, hoursSpent: 0, streak: 0 };
      }
    },
  });

  const enrollInCourse = async (courseId: string) => {
    try {
      await apiClient(`/api/courses/${courseId}/enroll`, {
        method: 'POST',
      });
      toast.success('Successfully enrolled in course!');
    } catch (error: any) {
      console.error('Enrollment error:', error);
      toast.error(error?.message || 'Failed to enroll in course');
    }
  };

  const getDifficultyColor = (difficulty: string) => {
    switch (difficulty?.toLowerCase()) {
      case 'beginner':
        return 'bg-green-100 text-green-800';
      case 'intermediate':
        return 'bg-yellow-100 text-yellow-800';
      case 'advanced':
        return 'bg-orange-100 text-orange-800';
      case 'expert':
        return 'bg-red-100 text-red-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const StatCard = ({ icon: Icon, title, value, subtitle, trend = undefined, gradient }: { icon: any; title: string; value: any; subtitle: string; trend?: number; gradient: string }) => (
    <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100 hover:shadow-xl hover:scale-105 transition-all duration-300">
      <div className="flex items-start justify-between mb-4">
        <div className={`p-4 rounded-xl bg-linear-to-br ${gradient}`}>
          <Icon className="w-7 h-7 text-white" />
        </div>
        {trend && (
          <div className={`flex items-center gap-1 px-2 py-1 rounded-full text-xs font-semibold ${trend > 0 ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
            <TrendingUp className="w-3 h-3" />
            {Math.abs(trend)}%
          </div>
        )}
      </div>
      <p className="text-gray-600 text-sm font-medium uppercase tracking-wide">{title}</p>
      <p className="text-4xl font-bold text-gray-900 mt-2">{value}</p>
      <p className="text-gray-500 text-xs mt-1">{subtitle}</p>
    </div>
  );

  const CourseCard = ({ course }: { course: Course }) => (
    <div
      onClick={() => setSelectedCourse(course)}
      className="bg-white rounded-2xl shadow-sm border border-gray-100 hover:shadow-lg hover:border-blue-200 transition-all duration-300 overflow-hidden cursor-pointer group"
    >
      {/* Course Header */}
      <div className={`h-32 bg-linear-to-br ${course.difficulty === 'advanced' ? 'from-red-400 to-red-600' : 'from-blue-400 to-blue-600'} p-4 text-white relative overflow-hidden`}>
        <div className="relative flex items-start justify-between">
          <div>
            <h3 className="text-xl font-bold text-white mb-1">{course.title}</h3>
            <p className="text-white/80 text-sm">{course.code}</p>
          </div>
        </div>
      </div>

      {/* Course Content */}
      <div className="p-4">
        <p className="text-gray-600 text-sm mb-3 line-clamp-2">{course.description}</p>

        <div className="flex flex-wrap gap-2 mb-4">
          <span className={`px-2 py-1 rounded-full text-xs font-medium ${getDifficultyColor(course.difficulty)}`}>
            {course.difficulty}
          </span>
          {course.category && (
            <span className="px-2 py-1 rounded-full text-xs font-medium bg-blue-100 text-blue-800">
              {course.category.name}
            </span>
          )}
        </div>

        {/* Course Stats */}
        <div className="flex items-center justify-between text-sm text-gray-500 mb-4 py-3 border-y border-gray-100">
          <div className="flex items-center gap-1">
            <Clock className="w-4 h-4" />
            <span>{course.estimated_hours}h</span>
          </div>
          <div className="flex items-center gap-1">
            <Users className="w-4 h-4" />
            <span>{course.enrollment_count} enrolled</span>
          </div>
          <div className="flex items-center gap-1">
            <Star className="w-4 h-4 fill-yellow-400 text-yellow-400" />
            <span>{course.rating.toFixed(1)}</span>
          </div>
        </div>

        {/* Instructor */}
        <p className="text-xs text-gray-500 mb-4">
          by {course.instructor?.name || 'Instructor'}
        </p>

        {/* Action Button */}
        {!course.is_enrolled ? (
          <button
            onClick={(e) => {
              e.stopPropagation();
              enrollInCourse(course.id);
            }}
            className="w-full px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors font-medium text-sm"
          >
            Enroll Now
          </button>
        ) : (
          <button
            className="w-full px-4 py-2 bg-green-100 text-green-700 rounded-lg font-medium text-sm cursor-default"
          >
            Enrolled
          </button>
        )}
      </div>
    </div>
  );

  if (coursesLoading) {
    return (
      <div className="min-h-screen bg-linear-to-br from-gray-50 via-blue-50/30 to-purple-50/30 p-4 md:p-6 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-32 w-32 border-b-2 border-blue-500 mx-auto mb-4" />
          <p className="text-gray-600">Loading courses...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-linear-to-br from-gray-50 via-blue-50/30 to-purple-50/30 p-4 md:p-6">
      <div className="max-w-7xl mx-auto space-y-6">
        
        {/* Stats Grid */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          <StatCard
            icon={BookOpen}
            title="Total Enrolled"
            value={courseStatistics.totalEnrolled}
            subtitle="Courses"
            gradient="from-blue-500 to-cyan-500"
          />
          <StatCard
            icon={CheckCircle}
            title="Completed"
            value={courseStatistics.completed}
            subtitle="Finished"
            gradient="from-green-500 to-emerald-500"
          />
          <StatCard
            icon={Clock}
            title="In Progress"
            value={courseStatistics.inProgress}
            subtitle="Active"
            trend={12}
            gradient="from-purple-500 to-pink-500"
          />
          <StatCard
            icon={Award}
            title="Avg Score"
            value={`${courseStatistics.avgScore}%`}
            subtitle="Overall"
            gradient="from-orange-500 to-red-500"
          />
        </div>

        {/* Filters Section */}
        <div className="bg-white rounded-2xl p-4 shadow-sm border border-gray-100">
          <div className="flex flex-wrap gap-4">
            <div className="flex-1 min-w-64">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-4 h-4" />
                <input
                  type="text"
                  placeholder="Search courses..."
                  value={filters.searchTerm}
                  onChange={(e) => setFilters({ ...filters, searchTerm: e.target.value })}
                  className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                />
              </div>
            </div>

            <select
              value={filters.difficulty}
              onChange={(e) => setFilters({ ...filters, difficulty: e.target.value })}
              className="px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              title="Filter by difficulty"
            >
              <option value="">All Levels</option>
              <option value="beginner">Beginner</option>
              <option value="intermediate">Intermediate</option>
              <option value="advanced">Advanced</option>
              <option value="expert">Expert</option>
            </select>

            <select
              value={filters.status}
              onChange={(e) => setFilters({ ...filters, status: e.target.value as any })}
              className="px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              title="Filter by status"
            >
              <option value="all">All Courses</option>
              <option value="enrolled">Enrolled</option>
              <option value="completed">Completed</option>
              <option value="recommended">Recommended</option>
            </select>
          </div>
        </div>

        {/* Courses Grid */}
        {coursesData.courses.length > 0 ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {coursesData.courses.map((course) => (
              <CourseCard key={course.id} course={course} />
            ))}
          </div>
        ) : (
          <div className="bg-white rounded-2xl p-12 shadow-sm border border-gray-100 text-center">
            <AlertCircle className="w-16 h-16 text-gray-400 mx-auto mb-4" />
            <h3 className="text-lg font-semibold text-gray-900 mb-2">No courses found</h3>
            <p className="text-gray-600 mb-4">Try adjusting your filters or search terms</p>
          </div>
        )}

        {/* Course Details Modal */}
        {selectedCourse && (
          <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
            <div className="bg-white rounded-2xl max-w-2xl w-full p-6 shadow-2xl max-h-[90vh] overflow-y-auto">
              <div className="flex items-start justify-between mb-4">
                <div>
                  <h2 className="text-2xl font-bold text-gray-900">{selectedCourse.title}</h2>
                  <p className="text-gray-600 text-sm mt-1">{selectedCourse.code}</p>
                </div>
                <button
                  onClick={() => setSelectedCourse(null)}
                  className="p-2 hover:bg-gray-100 rounded-lg"
                  title="Close"
                  aria-label="Close details"
                >
                  <X className="w-5 h-5" />
                </button>
              </div>

              <div className="space-y-4">
                <div>
                  <h3 className="font-semibold text-gray-900 mb-2">Description</h3>
                  <p className="text-gray-600">{selectedCourse.description}</p>
                </div>

                <div>
                  <h3 className="font-semibold text-gray-900 mb-2">Course Details</h3>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <p className="text-sm text-gray-500">Duration</p>
                      <p className="font-medium">{selectedCourse.estimated_hours}h</p>
                    </div>
                    <div>
                      <p className="text-sm text-gray-500">Difficulty</p>
                      <p className={`font-medium text-sm inline-block px-2 py-1 rounded-full ${getDifficultyColor(selectedCourse.difficulty)}`}>
                        {selectedCourse.difficulty}
                      </p>
                    </div>
                  </div>
                </div>

                <div>
                  <h3 className="font-semibold text-gray-900 mb-2">Enrollment</h3>
                  <p className="text-gray-600">{selectedCourse.enrollment_count} students enrolled</p>
                </div>

                <button
                  onClick={() => {
                    enrollInCourse(selectedCourse.id);
                    setSelectedCourse(null);
                  }}
                  disabled={selectedCourse.is_enrolled}
                  className="w-full px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors font-medium disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {selectedCourse.is_enrolled ? 'Already Enrolled' : 'Enroll Now'}
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

