'use client';

import React, { useState, useEffect } from 'react';
import { useParams } from 'next/navigation';
import { useLayoutStore } from '@/core/stores/useLayoutStore';
import { usePageHeader } from '@/core/providers/HeaderContext';
import { useCourseProgressStore } from '../hooks/useCourseProgressStore';
import { Breadcrumb } from '@/shared/components/ui/breadcrumb';
import { ProgressBar } from '@/shared/components/ui/ProgressBar';
import { PrerequisitesChecker } from './PrerequisitesChecker';
import { CourseSidebar } from './CourseSidebar';
import { CourseContent } from './CourseContent';
import { NotesPanel } from './NotesPanel';
import { DiscussionPanel } from './DiscussionPanel';
import { QuizPanel } from './QuizPanel';
import { useCourseData } from '../hooks/useCourseData';
import { useCourseNavigation } from '../hooks/useCourseNavigation';
import type { Lesson } from '@/shared/types';

export const EducationalCourseLayout = () => {
  const params = useParams();
  const courseId = params?.courseId as string;

  // --- STATE MANAGEMENT ---
  // Global UI state from Zustand
  const { sidebarOpen, toggleSidebar, activeCoursePanel, toggleCoursePanel } = useLayoutStore();
  // Page header hook
  const { setHeader } = usePageHeader();
  // Course progress state from Zustand
  const { progress, bookmarks, notes, markLessonComplete, toggleBookmark, saveNote } =
    useCourseProgressStore();
  // Local component state
  const [searchTerm, setSearchTerm] = useState('');
  const [offlineMode, setOfflineMode] = useState(false);
  const [showPrerequisites, setShowPrerequisites] = useState(true);
  const [prerequisitesMet, setPrerequisitesMet] = useState(false);

  // --- DATA FETCHING & HOOKS ---
  const { data: courseData, isLoading: isCourseLoading } = useCourseData(courseId);
  const {
    currentChapter,
    currentLesson,
    currentChapterIndex,
    currentLessonIndex,
    lessonKey,
    navigateTo,
    navigateNext,
    navigatePrev,
    isFirstLesson,
    isLastLesson,
  } = useCourseNavigation(courseData.chapters);

  // Set page header based on course data
  useEffect(() => {
    if (courseData?.title) {
      setHeader({
        title: courseData.title,
        description: courseData.description || 'Course content',
        icon: '📖',
      });
    }

    return () => {
      setHeader(null);
    };
  }, [courseData?.title, courseData?.description, setHeader]);

  // Online/offline detection
  useEffect(() => {
    const handleOnline = () => setOfflineMode(false);
    const handleOffline = () => setOfflineMode(true);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const getCurrentLesson = (): Lesson | undefined => {
    const chapter = courseData.chapters[currentChapterIndex];
    // Some sample/mock data uses numeric ids and lacks full fields; cast to the canonical Lesson
    // type to satisfy consumers. Consumers should treat some fields as optional where appropriate.
    return chapter ? (chapter.lessons[currentLessonIndex] as unknown as Lesson) : undefined;
  };

  // CourseContent expects a lightweight Lesson shape with numeric id and string duration.
  const toContentLesson = (l?: Lesson) => {
    if (!l) return undefined;
    return {
      id: Number((l as any).id) || 0,
      title: (l as any).title || '',
      type: (l as any).type || 'text',
      duration:
        typeof (l as any).duration === 'number'
          ? `${(l as any).duration}m`
          : String((l as any).duration || ''),
      content: ((): any => {
        const c = (l as any).content;
        if (!c) return { text: '' };
        if (typeof c === 'string') return { text: c };
        return c;
      })(),
    };
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      <div className="flex flex-1">
        <CourseSidebar
          chapters={courseData.chapters}
          resources={courseData.resources}
          currentChapterIndex={currentChapterIndex}
          currentLessonIndex={currentLessonIndex}
          navigateTo={navigateTo}
          progress={progress}
          toggleCoursePanel={toggleCoursePanel}
        />

        {/* Main Content */}
        <main className="flex-1 p-6">
          <Breadcrumb />
          <ProgressBar value={50} />

          {/* Prerequisites Checker */}
          {showPrerequisites && courseId && (
            <div className="mb-6">
              <PrerequisitesChecker courseId={courseId} onPrerequisitesMet={setPrerequisitesMet} />
            </div>
          )}

          <CourseContent
            currentLesson={toContentLesson(getCurrentLesson())}
            lessonKey={lessonKey}
            offlineMode={offlineMode}
            bookmarks={bookmarks}
            progress={progress}
            toggleBookmark={toggleBookmark}
            markLessonComplete={markLessonComplete}
            navigatePrev={navigatePrev}
            navigateNext={navigateNext}
            isFirstLesson={isFirstLesson}
            isLastLesson={isLastLesson}
          />

          {activeCoursePanel === 'notes' && (
            <NotesPanel lessonKey={lessonKey} notes={notes} saveNote={saveNote} />
          )}
          {activeCoursePanel === 'discussion' && (
            <DiscussionPanel discussions={courseData.discussions} />
          )}
          {activeCoursePanel === 'quiz' && <QuizPanel />}
        </main>
      </div>
    </div>
  );
};

