import { useState, useEffect } from 'react';
import { apiService } from '@/features/auth/services/apiClient';
import { Course, CourseModule } from '@/shared/types/courseInterface';
import { Module } from '@/features/courses/types/courseTypes';

export const useCourseModules = (courseId: string) => {
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [modules, setModules] = useState<Module[]>([]);
  const [courseTitle, setCourseTitle] = useState('');

  useEffect(() => {
    const fetchCourseModules = async () => {
      try {
        setIsLoading(true);
        setError(null);
        const [courseResponse, modulesResponse] = await Promise.all([
          apiService.get<Course>(`/courses/${courseId}`),
          apiService.get<CourseModule[]>(`/courses/${courseId}/modules`),
        ]);
        setCourseTitle(courseResponse.data.title);
        setModules(modulesResponse.data);
      } catch (err: any) {
        setError(err.message || 'Failed to load course modules');
      } finally {
        setIsLoading(false);
      }
    };

    fetchCourseModules();
  }, [courseId]);

  return { modules, courseTitle, isLoading, error };
};

import { useState } from 'react';

export const useCourseNavigation = (chapters: any[]) => {
  const [currentChapterIndex, setCurrentChapterIndex] = useState(0);
  const [currentLessonIndex, setCurrentLessonIndex] = useState(0);

  const currentChapter = chapters?.[currentChapterIndex];
  const currentLesson = currentChapter?.lessons?.[currentLessonIndex];
  const lessonKey = `${currentChapter?.id}-${currentLesson?.id}`;

  const navigateTo = (chapterIndex: number, lessonIndex: number) => {
    if (chapters?.[chapterIndex]?.lessons?.[lessonIndex]) {
      setCurrentChapterIndex(chapterIndex);
      setCurrentLessonIndex(lessonIndex);
    }
  };

  const navigateNext = () => {
    if (currentLessonIndex < currentChapter.lessons.length - 1) {
      navigateTo(currentChapterIndex, currentLessonIndex + 1);
    } else if (currentChapterIndex < chapters.length - 1) {
      navigateTo(currentChapterIndex + 1, 0);
    }
  };

  const navigatePrev = () => {
    if (currentLessonIndex > 0) {
      navigateTo(currentChapterIndex, currentLessonIndex - 1);
    } else if (currentChapterIndex > 0) {
      const prevChapter = chapters[currentChapterIndex - 1];
      navigateTo(currentChapterIndex - 1, prevChapter.lessons.length - 1);
    }
  };

  const isFirstLesson = currentChapterIndex === 0 && currentLessonIndex === 0;
  const isLastLesson =
    currentChapterIndex === chapters.length - 1 &&
    currentLessonIndex === currentChapter.lessons.length - 1;

  return {
    currentChapter,
    currentLesson,
    currentChapterIndex,
    currentLessonIndex,
    lessonKey,
    navigateTo,
    navigateNext,
    navigatePrev,
    isFirstLesson,
    isLastLesson,
  };
};

'use client';

import React, { useState, useEffect } from 'react';
import {
  Target,
  Calendar,
  Clock,
  BookOpen,
  TrendingUp,
  CheckCircle,
  ArrowRight,
  ArrowLeft,
  X,
  Lightbulb,
  Star,
  AlertCircle,
} from 'lucide-react';

interface GoalCreationWizardProps {
  isOpen: boolean;
  onClose: () => void;
  onGoalCreated: () => void;
}

interface SMARTSuggestions {
  specific: string;
  measurable: string;
  achievable: string;
  relevant: string;
  time_bound: string;
}

export const GoalCreationWizard: React.FC<GoalCreationWizardProps> = ({
  isOpen,
  onClose,
  onGoalCreated,
}) => {
  const [currentStep, setCurrentStep] = useState(1);
  const [goalData, setGoalData] = useState({
    title: '',
    description: '',
    type: 'custom',
    category: 'custom',
    priority: 'medium',
    target_criteria: {
      type: 'numeric',
      target_value: 0,
      unit: '',
      measurement_method: '',
    },
    start_date: new Date().toISOString().split('T')[0],
    target_date: '',
    learning_path_id: '',
    course_id: '',
    smart_criteria: {
      specific: '',
      measurable: '',
      achievable: '',
      relevant: '',
      time_bound: '',
    },
    milestones: [] as any[],
    reminder_settings: {
      enabled: true,
      frequency: 'daily' as const,
      time: '09:00',
    },
    progress_tracking: {
      auto_tracking: false,
      manual_updates: true,
      data_sources: [] as string[],
      update_frequency: 'manual' as const,
    },
  });
  const [smartSuggestions, setSmartSuggestions] = useState<SMARTSuggestions | null>(null);
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState<{ [key: string]: string }>({});

  const steps = [
    { id: 1, title: 'Goal Basics', description: 'Define your goal' },
    { id: 2, title: 'SMART Criteria', description: 'Make it specific and measurable' },
    { id: 3, title: 'Timeline & Milestones', description: 'Set deadlines and checkpoints' },
    { id: 4, title: 'Tracking & Reminders', description: 'Configure progress tracking' },
    { id: 5, title: 'Review & Create', description: 'Confirm your goal' },
  ];

  useEffect(() => {
    if (currentStep === 2 && goalData.title && goalData.category) {
      generateSMARTSuggestions();
    }
  }, [currentStep, goalData.title, goalData.category]);

  const generateSMARTSuggestions = async () => {
    try {
      const response = await fetch(`/api/learning-goals/smart-suggestions`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          title: goalData.title,
          category: goalData.category,
          target_criteria: goalData.target_criteria,
        }),
      });

      if (response.ok) {
        const suggestions = await response.json();
        setSmartSuggestions(suggestions?.data || suggestions);
        setGoalData(prev => ({
          ...prev,
          smart_criteria: suggestions?.data || suggestions,
        }));
      }
    } catch (error) {
      console.error('Error generating SMART suggestions:', error);
    }
  };

  const validateStep = (step: number): boolean => {
    const newErrors: { [key: string]: string } = {};

    switch (step) {
      case 1:
        if (!goalData.title.trim()) newErrors.title = 'Title is required';
        if (!goalData.description.trim()) newErrors.description = 'Description is required';
        if (!goalData.target_criteria.target_value)
          newErrors.target_value = 'Target value is required';
        break;

      case 2:
        if (!goalData.smart_criteria.specific.trim())
          newErrors.specific = 'Specific criteria is required';
        if (!goalData.smart_criteria.measurable.trim())
          newErrors.measurable = 'Measurable criteria is required';
        break;

      case 3:
        if (!goalData.target_date) newErrors.target_date = 'Target date is required';
        if (new Date(goalData.target_date) <= new Date(goalData.start_date)) {
          newErrors.target_date = 'Target date must be after start date';
        }
        break;
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const nextStep = () => {
    if (validateStep(currentStep)) {
      setCurrentStep(prev => Math.min(prev + 1, steps.length));
    }
  };

  const prevStep = () => {
    setCurrentStep(prev => Math.max(prev - 1, 1));
  };

  const createGoal = async () => {
    if (!validateStep(currentStep)) return;

    try {
      setLoading(true);
      const response = await fetch(`/api/learning-goals`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          ...goalData,
          start_date: new Date(goalData.start_date),
          target_date: new Date(goalData.target_date),
        }),
      });

      if (response.ok) {
        onGoalCreated();
        onClose();
        resetForm();
      } else {
        const error = await response.json();
        setErrors({ general: error.message || 'Failed to create goal' });
      }
    } catch (error) {
      setErrors({ general: 'Failed to create goal' });
    } finally {
      setLoading(false);
    }
  };

  const resetForm = () => {
    setCurrentStep(1);
    setGoalData({
      title: '',
      description: '',
      type: 'custom',
      category: 'custom',
      priority: 'medium',
      target_criteria: {
        type: 'numeric',
        target_value: 0,
        unit: '',
        measurement_method: '',
      },
      start_date: new Date().toISOString().split('T')[0],
      target_date: '',
      learning_path_id: '',
      course_id: '',
      smart_criteria: {
        specific: '',
        measurable: '',
        achievable: '',
        relevant: '',
        time_bound: '',
      },
      milestones: [],
      reminder_settings: {
        enabled: true,
        frequency: 'daily',
        time: '09:00',
      },
      progress_tracking: {
        auto_tracking: false,
        manual_updates: true,
        data_sources: [],
        update_frequency: 'manual',
      },
    });
    setErrors({});
    setSmartSuggestions(null);
  };

  const addMilestone = () => {
    const newMilestone = {
      title: '',
      description: '',
      target_date: goalData.target_date,
      target_value: goalData.target_criteria.target_value / 2,
      order: goalData.milestones.length,
    };
    setGoalData(prev => ({
      ...prev,
      milestones: [...prev.milestones, newMilestone],
    }));
  };

  const updateMilestone = (index: number, field: string, value: any) => {
    setGoalData(prev => ({
      ...prev,
      milestones: prev.milestones.map((milestone, i) =>
        i === index ? { ...milestone, [field]: value } : milestone
      ),
    }));
  };

  const removeMilestone = (index: number) => {
    setGoalData(prev => ({
