'use client';

import React, { useState, useEffect } from 'react';
import { usePageHeader } from '@/core/providers/HeaderContext';
import {
  BookOpen,
  Target,
  Clock,
  Users,
  Star,
  Play,
  Pause,
  CheckCircle,
  TrendingUp,
  Award,
  Filter,
  Search,
  Grid,
  List,
} from 'lucide-react';

interface LearningPath {
  id: string;
  title: string;
  description: string;
  category: string;
  difficulty: string;
  status: string;
  estimated_duration_weeks: number;
  estimated_hours_per_week: number;
  tags: string[];
  learning_objectives: string[];
  analytics: {
    total_enrollments: number;
    completion_rate: number;
    user_ratings: {
      average: number;
      count: number;
    };
  };
  created_by: {
    id: string;
    first_name: string;
    last_name: string;
  };
  courses: any[];
  milestones: any[];
}

interface LearningPathProgress {
  id: string;
  status: string;
  overall_progressPercentage: number;
  started_at: string;
  last_accessed_at: string;
  learning_path: LearningPath;
}

export const LearningPathInterface: React.FC = () => {
  const { setHeader } = usePageHeader();
  const [learningPaths, setLearningPaths] = useState<LearningPath[]>([]);
  const [userProgress, setUserProgress] = useState<LearningPathProgress[]>([]);
  const [loading, setLoading] = useState(true);
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [filters, setFilters] = useState({
    category: '',
    difficulty: '',
    status: '',
    search: '',
  });
  const [activeTab, setActiveTab] = useState<'browse' | 'my-paths' | 'recommendations'>('browse');

  useEffect(() => {
    // Set page header
    setHeader({
      title: 'Learning Paths',
      description: 'Structured learning journeys to help you achieve your medical education goals',
      icon: '📚',
    });

    return () => {
      // Clear header when component unmounts
      setHeader(null);
    };
  }, [setHeader]);

  useEffect(() => {
    fetchLearningPaths();
    fetchUserProgress();
  }, [filters]);

  const fetchLearningPaths = async () => {
    try {
      setLoading(true);
      const queryParams = new URLSearchParams();
      Object.entries(filters).forEach(([key, value]) => {
        if (value) queryParams.append(key, value);
      });

      const response = await fetch(`/api/learning-paths?${queryParams}`);
      if (!response.ok) {
        throw new Error(`API error: ${response.status}`);
      }
      const data = await response.json();

      // Handle various response formats
      let pathsData: LearningPath[] = [];
      if (Array.isArray(data)) {
        pathsData = data;
      } else if (data?.data && Array.isArray(data.data)) {
        pathsData = data.data;
      } else if (data?.learningPaths && Array.isArray(data.learningPaths)) {
        pathsData = data.learningPaths;
      } else {
        console.warn('API response for learning paths is in unexpected format:', data);
        pathsData = [];
      }

      setLearningPaths(pathsData);
    } catch (error) {
      console.error('Error fetching learning paths:', error);
      setLearningPaths([]);
    } finally {
      setLoading(false);
    }
  };

  const fetchUserProgress = async () => {
    try {
      const response = await fetch(`/api/learning-paths/my-progress`);
      const data = await response.json();
      const pathsData = data?.data || data;
      if (Array.isArray(pathsData)) {
        setUserProgress(pathsData);
      } else {
        console.error('API response for user progress is not an array:', data);
      }
    } catch (error) {
      console.error('Error fetching user progress:', error);
    }
  };

  const enrollInPath = async (pathId: string) => {
    try {
      const response = await fetch(`/api/learning-paths/${pathId}/enroll`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          preferences: {
            daily_study_goal_minutes: 60,
            reminder_settings: { enabled: true, frequency: 'daily', time: '09:00' },
          },
        }),
      });

      if (response.ok) {
        fetchUserProgress();
        // Show success notification
      }
    } catch (error) {
      console.error('Error enrolling in path:', error);
    }
  };

  const getDifficultyColor = (difficulty: string) => {
    switch (difficulty.toLowerCase()) {
      case 'beginner':
        return 'bg-green-100 text-green-800';
      case 'intermediate':
        return 'bg-yellow-100 text-yellow-800';
      case 'advanced':
        return 'bg-orange-100 text-orange-800';
      case 'expert':
        return 'bg-red-100 text-red-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'notStarted':
        return 'bg-gray-100 text-gray-800';
      case 'inProgress':
        return 'bg-blue-100 text-blue-800';
      case 'completed':
        return 'bg-green-100 text-green-800';
      case 'paused':
        return 'bg-yellow-100 text-yellow-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const renderPathCard = (path: LearningPath, progress?: LearningPathProgress) => {
    const isEnrolled = !!progress;

    return (
      <div
        key={path.id}
        className="bg-white rounded-lg shadow-sm border border-gray-200 hover:shadow-md transition-shadow"
      >
        <div className="p-6">
          <div className="flex items-start justify-between mb-4">
            <div className="flex-1">
              <h3 className="text-lg font-semibold text-gray-900 mb-2">{path.title}</h3>
              <p className="text-gray-600 text-sm mb-3 line-clamp-2">{path.description}</p>

              <div className="flex flex-wrap gap-2 mb-3">
                <span
                  className={`px-2 py-1 rounded-full text-xs font-medium ${getDifficultyColor(path.difficulty)}`}
                >
                  {path.difficulty}
                </span>
                <span className="px-2 py-1 rounded-full text-xs font-medium bg-blue-100 text-blue-800">
                  {path.category.replace('_', ' ')}
                </span>
                {isEnrolled && (
                  <span
                    className={`px-2 py-1 rounded-full text-xs font-medium ${getStatusColor(progress.status)}`}
                  >
                    {progress.status
                      .replace(/([A-Z])/g, ' $1')
                      .replace(/^./, str => str.toUpperCase())}
                  </span>
                )}
              </div>
            </div>

            <div className="flex items-center space-x-1 text-yellow-400">
              <Star className="w-4 h-4 fill-current" />
              <span className="text-sm text-gray-600">
                {path.analytics.user_ratings.average.toFixed(1)} (
                {path.analytics.user_ratings.count})
              </span>
            </div>
          </div>

          {isEnrolled && (
            <div className="mb-4">
              <div className="flex items-center justify-between text-sm text-gray-600 mb-1">
                <span>Progress</span>
                <span>{Math.round(progress.overall_progressPercentage)}%</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div
                  className="bg-blue-600 h-2 rounded-full transition-all duration-300"
                  style={{ width: `${progress.overall_progressPercentage}%` }}
                />
              </div>
            </div>
          )}

          <div className="flex items-center justify-between text-sm text-gray-500 mb-4">
            <div className="flex items-center space-x-4">
              <div className="flex items-center space-x-1">
                <Clock className="w-4 h-4" />
                <span>{path.estimated_duration_weeks}w</span>
              </div>
              <div className="flex items-center space-x-1">
                <BookOpen className="w-4 h-4" />
                <span>{path.courses.length} courses</span>
              </div>
              <div className="flex items-center space-x-1">
                <Users className="w-4 h-4" />
                <span>{path.analytics.total_enrollments}</span>
              </div>
            </div>

            <div className="flex items-center space-x-1">
              <TrendingUp className="w-4 h-4" />
              <span>{Math.round(path.analytics.completion_rate)}% completion</span>
            </div>
          </div>

          <div className="flex items-center justify-between">
            <div className="text-sm text-gray-500">
              by {path.created_by.first_name} {path.created_by.last_name}
            </div>

            <div className="flex space-x-2">
              {isEnrolled ? (
                <>
                  {progress.status === 'paused' ? (
                    <button className="px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors flex items-center space-x-1">
                      <Play className="w-4 h-4" />
                      <span>Resume</span>
                    </button>
                  ) : progress.status === 'completed' ? (
                    <button className="px-4 py-2 bg-gray-600 text-white rounded-lg flex items-center space-x-1">
                      <CheckCircle className="w-4 h-4" />
                      <span>Completed</span>
                    </button>
                  ) : (
                    <button className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors">
                      Continue
                    </button>
                  )}
                </>
              ) : (
                <button
                  onClick={() => enrollInPath(path.id)}
                  className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
                >
                  Enroll
                </button>
              )}
            </div>
          </div>
        </div>
      </div>
    );
  };

  const renderFilters = () => (
    <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-4 mb-6">
      <div className="flex flex-wrap gap-4">
        <div className="flex-1 min-w-64">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-4 h-4" />
            <input
              type="text"
              placeholder="Search learning paths..."
              value={filters.search}
              onChange={e => setFilters({ ...filters, search: e.target.value })}
              className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
          </div>
        </div>

        <select
          value={filters.category}
          onChange={e => setFilters({ ...filters, category: e.target.value })}
          className="px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
        >
          <option value="">All Categories</option>
          <option value="usmle_step1">USMLE Step 1</option>
          <option value="usmle_step2">USMLE Step 2</option>
          <option value="clinical_skills">Clinical Skills</option>
          <option value="specialty_prep">Specialty Prep</option>
        </select>

        <select
          value={filters.difficulty}
          onChange={e => setFilters({ ...filters, difficulty: e.target.value })}
          className="px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
        >
          <option value="">All Levels</option>
          <option value="beginner">Beginner</option>
          <option value="intermediate">Intermediate</option>
          <option value="advanced">Advanced</option>
          <option value="expert">Expert</option>
        </select>

        <div className="flex items-center space-x-2">
          <button
            onClick={() => setViewMode('grid')}
            className={`p-2 rounded-lg ${viewMode === 'grid' ? 'bg-blue-100 text-blue-600' : 'text-gray-400 hover:text-gray-600'}`}
          >
            <Grid className="w-4 h-4" />
          </button>
          <button
            onClick={() => setViewMode('list')}
            className={`p-2 rounded-lg ${viewMode === 'list' ? 'bg-blue-100 text-blue-600' : 'text-gray-400 hover:text-gray-600'}`}
          >
            <List className="w-4 h-4" />
          </button>
        </div>
      </div>
    </div>
  );

  const renderTabContent = () => {
    switch (activeTab) {
      case 'my-paths':
        return (
          <div
            className={
              viewMode === 'grid'
                ? 'grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6'
                : 'space-y-4'
            }
          >
            {userProgress.map(progress => renderPathCard(progress.learning_path, progress))}
          </div>
        );

      case 'recommendations':
        // This would fetch recommended paths
        return (
          <div
            className={
              viewMode === 'grid'
                ? 'grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6'
                : 'space-y-4'
            }
          >
            {learningPaths.slice(0, 6).map(path => renderPathCard(path))}
          </div>
        );

      default:
        return (
          <div
            className={
              viewMode === 'grid'
                ? 'grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6'
                : 'space-y-4'
            }
          >
            {learningPaths.map(path => {
              const progress = userProgress.find(p => p.learning_path.id === path.id);
              return renderPathCard(path, progress);
            })}
          </div>
        );
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      {/* Tabs */}
      <div className="border-b border-gray-200 mb-6">
        <nav className="-mb-px flex space-x-8">
          {[
            { id: 'browse', label: 'Browse All', icon: BookOpen },
            { id: 'my-paths', label: 'My Paths', icon: Target },
            { id: 'recommendations', label: 'Recommended', icon: Award },
          ].map(tab => {
            const Icon = tab.icon;
            return (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`flex items-center space-x-2 py-2 px-1 border-b-2 font-medium text-sm ${
                  activeTab === tab.id
                    ? 'border-blue-500 text-blue-600'
                    : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                }`}
              >
                <Icon className="w-4 h-4" />
                <span>{tab.label}</span>
              </button>
            );
          })}
        </nav>
      </div>

      {renderFilters()}

      {loading ? (
        <div className="flex items-center justify-center py-12">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
        </div>
      ) : (
        renderTabContent()
      )}
    </div>
  );
};

'use client';

import React, { useState, useEffect } from 'react';
import ProgressBar from '@/shared/components/ui/ProgressBar';
import Link from 'next/link';
import {
  Route,
  TrendingUp,
  Clock,
  Target,
  ChevronRight,
  Play,
  CheckCircle,
  Award,
} from 'lucide-react';
import { LearningPathProgress } from '@/shared/types/learningInterface';
import { learningPathService } from '@/features/learning-management/services/learningPathService';

export const LearningPathProgressWidget: React.FC = () => {
  const [pathProgress, setPathProgress] = useState<LearningPathProgress[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchPathProgress();
  }, []);

  const fetchPathProgress = async () => {
    try {
      const data = await learningPathService.getMyProgress();
      if (Array.isArray(data)) {
        setPathProgress(data.slice(0, 3)); // Show top 3 active paths
      } else {
        console.error('API response is not an array:', data);
      }
    } catch (error) {
      console.error('Error fetching learning path progress:', error);
    } finally {
      setLoading(false);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'inProgress':
        return 'text-blue-600 bg-blue-100';
      case 'completed':
        return 'text-green-600 bg-green-100';
      case 'paused':
        return 'text-yellow-600 bg-yellow-100';
      default:
        return 'text-gray-600 bg-gray-100';
    }
  };

  const formatTimeAgo = (dateString: string) => {
    const date = new Date(dateString);
    const now = new Date();
    const diffInHours = Math.floor((now.getTime() - date.getTime()) / (1000 * 60 * 60));

    if (diffInHours < 1) return 'Just now';
    if (diffInHours < 24) return `${diffInHours}h ago`;
    const diffInDays = Math.floor(diffInHours / 24);
    if (diffInDays < 7) return `${diffInDays}d ago`;
    const diffInWeeks = Math.floor(diffInDays / 7);
    return `${diffInWeeks}w ago`;
  };

  if (loading) {
    return (
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
        <div className="flex items-center space-x-3 mb-4">
          <div className="p-2 bg-blue-100 rounded-lg">
            <Route className="w-5 h-5 text-blue-600" />
          </div>
          <h3 className="text-lg font-semibold text-gray-900">Learning Paths</h3>
        </div>
        <div className="animate-pulse space-y-4">
          {[...Array(3)].map((_, i) => (
            <div key={i} className="h-16 bg-gray-100 rounded-lg"></div>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center space-x-3">
          <div className="p-2 bg-blue-100 rounded-lg">
            <Route className="w-5 h-5 text-blue-600" />
          </div>
          <h3 className="text-lg font-semibold text-gray-900">Learning Paths</h3>
        </div>
        <Link
          href="/learning-paths"
          className="text-blue-600 hover:text-blue-700 text-sm font-medium flex items-center space-x-1"
        >
          <span>View All</span>
          <ChevronRight className="w-4 h-4" />
        </Link>
      </div>

      {pathProgress.length === 0 ? (
        <div className="text-center py-8">
          <Route className="w-12 h-12 text-gray-400 mx-auto mb-3" />
          <h4 className="text-lg font-medium text-gray-900 mb-2">No Active Learning Paths</h4>
          <p className="text-gray-500 mb-4">
            Start your structured learning journey with curated educational paths
          </p>
          <Link
            href="/learning-paths"
            className="inline-flex items-center space-x-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors"
          >
            <Route className="w-4 h-4" />
            <span>Browse Learning Paths</span>
          </Link>
        </div>
      ) : (
        <div className="space-y-4">
          {pathProgress.map(progress => (
            <Link
              key={progress.id}
              href={`/learning-paths/${progress.learning_path.id}`}
              className="block p-4 border border-gray-200 rounded-lg hover:border-blue-300 hover:shadow-sm transition-all"
            >
              <div className="flex items-start justify-between mb-3">
                <div className="flex-1">
                  <h4 className="font-medium text-gray-900 mb-1">{progress.learning_path.title}</h4>
                  <div className="flex items-center space-x-3 text-sm text-gray-500">
                    <span className="capitalize">
                      {progress.learning_path.category.replace('_', ' ')}
                    </span>
                    <span>•</span>
                    <div className="flex items-center space-x-1">
                      <Clock className="w-3 h-3" />
                      <span>{progress.learning_path.estimated_duration_weeks}w</span>
                    </div>
                    <span>•</span>
                    <span>Last active {formatTimeAgo(progress.last_accessed_at)}</span>
                  </div>
                </div>

                <div className="flex items-center space-x-2">
                  <span
                    className={`px-2 py-1 rounded-full text-xs font-medium ${getStatusColor(progress.status)}`}
                  >
                    {progress.status
                      .replace(/([A-Z])/g, ' $1')
                      .replace(/^./, str => str.toUpperCase())}
                  </span>

                  {progress.status === 'completed' ? (
                    <CheckCircle className="w-5 h-5 text-green-600" />
                  ) : (
                    <Play className="w-5 h-5 text-blue-600" />
                  )}
                </div>
              </div>

              <div className="mb-3">
                <div className="flex items-center justify-between text-sm text-gray-600 mb-1">
                  <span>Progress</span>
                  <span>{Math.round(progress.overall_progressPercentage)}%</span>
                </div>
                <div className="w-full h-2">
                  <ProgressBar
                    value={progress.overall_progressPercentage}
                    className="h-2 rounded-full"
                    colorClass={progress.status === 'completed' ? 'bg-green-600' : 'bg-blue-600'}
                  />
                </div>
              </div>

              {progress.milestones_achieved.length > 0 && (
                <div className="flex items-center space-x-2 text-sm text-gray-600">
                  <Award className="w-4 h-4 text-yellow-600" />
                  <span>
                    {progress.milestones_achieved.length} of{' '}
                    {progress.learning_path.milestones?.length || 0} milestones achieved
                  </span>
                </div>
