interface Milestone {
  id: string;
  title: string;
  description: string;
  type: string;
  rewards?: {
    points?: number;
    badge_id?: string;
    certificate?: {
      template_id: string;
      title: string;
      description: string;
    };
    unlock_content?: {
      courses?: string[];
      assessments?: string[];
      clinical_cases?: string[];
    };
  };
  celebration_config?: {
    show_animation: boolean;
    animation_type: 'confetti' | 'fireworks' | 'badge' | 'custom';
    message: string;
    auto_share: boolean;
  };
}

interface MilestoneCelebrationProps {
  milestone: Milestone;
  isVisible: boolean;
  onClose: () => void;
  onShare?: () => void;
  onDownloadCertificate?: () => void;
}

export const MilestoneCelebration: React.FC<MilestoneCelebrationProps> = ({
  milestone,
  isVisible,
  onClose,
  onShare,
  onDownloadCertificate,
}) => {
  const [showConfetti, setShowConfetti] = useState(false);
  const [animationPhase, setAnimationPhase] = useState<'enter' | 'celebrate' | 'exit'>('enter');

  useEffect(() => {
    if (isVisible) {
      setAnimationPhase('enter');

      // Show confetti animation
      if (milestone.celebration_config?.animation_type === 'confetti') {
        setTimeout(() => setShowConfetti(true), 500);
      }

      // Transition to celebration phase
      setTimeout(() => setAnimationPhase('celebrate'), 1000);
    }
  }, [isVisible, milestone]);

  const getMilestoneIcon = (type: string) => {
    switch (type) {
      case 'phase_completion':
        return Trophy;
      case 'assessment_score':
        return Star;
      case 'time_based':
        return Target;
      case 'skill_mastery':
        return Medal;
      case 'streak_achievement':
        return Crown;
      default:
        return Award;
    }
  };

  const getAnimationClass = () => {
    switch (animationPhase) {
      case 'enter':
        return 'animate-bounce';
      case 'celebrate':
        return 'animate-pulse';
      case 'exit':
        return 'animate-fade-out';
      default:
        return '';
    }
  };

  const renderConfetti = () => {
    if (!showConfetti) return null;

    return (
      <div className="absolute inset-0 pointer-events-none overflow-hidden">
        {[...Array(50)].map((_, i) => (
          <div
            key={i}
            className="absolute animate-confetti"
            style={{
