  };

  const renderRewards = () => {
    if (!milestone.rewards) return null;

    return (
      <div className="space-y-4">
        {milestone.rewards.points && (
          <div className="flex items-center justify-center space-x-2 bg-yellow-50 border border-yellow-200 rounded-lg p-3">
