          <X className="w-5 h-5" />
        </button>

        {/* Header with gradient background */}
        <div className="relative bg-gradient-to-br from-blue-500 via-purple-500 to-pink-500 p-8 text-center">
          <div className="absolute inset-0 bg-black bg-opacity-10"></div>

          <div className="relative z-10">
            <div className="inline-flex items-center justify-center w-20 h-20 bg-white bg-opacity-20 rounded-full mb-4 backdrop-blur-sm">
              <Icon className="w-10 h-10 text-white" />
