import api from '../../auth/services/apiClient';
import {
  CourseProgress,
  ProgressData,
  ProgressStats,
  Activity,
  Achievement,
} from '@/features/learning-management/interfaces/progress.interface';
import { toast } from 'sonner';

const progressService = {
  async getProgressStats(userId: string): Promise<ProgressStats> {
    try {
      const response = await api.get<ProgressStats>(`/progress/overview/${userId}`);
      return response.data as ProgressStats;
    } catch (error) {
      console.error('Error fetching progress stats:', error);

      // Return placeholder data if API fails
      return {
        overallProgress: 48,
        coursesCompleted: 7,
        totalCourses: 15,
        streak: 12,
        lastActivity: new Date().toISOString(),
      };
    }
  },

  async getUserProgress(userId: string): Promise<any[]> {
    try {
      const response = await api.get<any[]>(`/progress/user-progress/${userId}`);
      return response.data;
    } catch (error) {
      console.error('Error fetching user progress:', error);
      throw error;
    }
  },

  async getCourseProgress(userId: string): Promise<CourseProgress[]> {
    try {
      const response = await api.get<CourseProgress[]>(`/progress/courses/${userId}`);
      return response.data;
    } catch (error) {
      console.error('Error fetching course progress:', error);
      return []; // Return empty array on error
    }
  },

  async getRecentActivities(): Promise<Activity[]> {
    try {
      const response = await api.get<any[]>('/progress/activities');
      const raw = response.data;
      const normalize = (item: any): Activity => {
        // Accept multiple backend shapes and normalize to the frontend Activity type
        const date = item.date || item.createdAt || item.timestamp || new Date().toISOString();
        const title = item.title || item.name || item.description || 'Activity';
        const type = item.type || item.kind || 'activity';
        // duration might be in minutes or seconds or nested
        let durationMinutes: number | undefined = undefined;
        if (typeof item.durationMinutes === 'number') durationMinutes = item.durationMinutes;
        else if (typeof item.duration === 'number') durationMinutes = item.duration;
        else if (item.session && typeof item.session.duration === 'number')
          durationMinutes = item.session.duration;
        else if (item.metadata && typeof item.metadata.duration === 'number')
          durationMinutes = item.metadata.duration;
        // if duration looks like seconds and large, try normalize to minutes
        if (typeof durationMinutes === 'number' && durationMinutes > 1000) {
          durationMinutes = Math.round(durationMinutes / 60);
        }

        let score: number | undefined = undefined;
        if (typeof item.score === 'number') score = item.score;
        else if (item.metadata && typeof item.metadata.score === 'number')
          score = item.metadata.score;
        else if (item.session && typeof item.session.score === 'number') score = item.session.score;

        return {
          id: item.id || item._id || `${Math.random().toString(36).slice(2)}${Date.now()}`,
          type,
          title,
          date,
          durationMinutes,
          score,
        } as Activity;
      };

      return Array.isArray(raw) ? raw.map(normalize) : [];
    } catch (error) {
      console.error('Error fetching recent activities:', error);

      // Return placeholder data if API fails
      return [
        {
          id: '1',
          type: 'course',
          title: 'Completed quiz in Physiology Fundamentals',
          date: new Date().toISOString(),
          durationMinutes: 30,
          score: 88,
        },
        {
          id: '2',
          type: 'material',
          title: 'Downloaded Anatomy Lecture Notes',
          date: new Date(Date.now() - 3600000).toISOString(),
          durationMinutes: 10,
        },
      ];
    }
  },

  async getAchievements(): Promise<Achievement[]> {
    try {
      const response = await api.get<Achievement[]>('/progress/achievements');
      return response.data as Achievement[];
    } catch (error) {
      console.error('Error fetching achievements:', error);

      // Return placeholder data if API fails
      return [
        {
          id: '1',
          title: 'Fast Learner',
          description: 'Completed 5 courses',
          icon: 'trophy',
          dateEarned: new Date(Date.now() - 86400000 * 7).toISOString(),
        },
        {
          id: '2',
          title: 'Consistent Student',
          description: 'Maintained a 10-day streak',
          icon: 'calendar',
          dateEarned: new Date().toISOString(),
        },
      ];
    }
  },

  async getAllProgressData(userId: string): Promise<ProgressData> {
    try {
      // Fetch data from multiple endpoints in parallel
      const [overviewRes, coursesRes, activitiesRes, achievementsRes] = await Promise.all([
        api.get<ProgressStats>(`/progress/overview/${userId}`).catch(() => null),
        api.get<CourseProgress[]>(`/progress/courses/${userId}`).catch(() => null),
        api.get<Activity[]>('/progress/activities').catch(() => null),
        api.get<Achievement[]>('/progress/achievements').catch(() => null),
      ]);

      const stats: ProgressStats = overviewRes?.data || { overallProgress: 0, coursesCompleted: 0, totalCourses: 0, streak: 0, lastActivity: null };
      const courseProgress = coursesRes?.data || [];
      const recentActivities = activitiesRes?.data || [];
      const achievements = achievementsRes?.data || [];

      return {
        overallProgress: stats.overallProgress || 0,
        stats: {
          overallProgress: stats.overallProgress || 0,
          coursesCompleted: stats.coursesCompleted || 0,
          totalCourses: stats.totalCourses || 0,
          averageScore: (stats as any).averageScore || 0, // Keep averageScore if it exists
          streak: stats.streak || 0,
          lastActivity: stats.lastActivity || new Date().toISOString(),
        },
        coursesCompleted: stats.coursesCompleted || 0,
        totalCourses: stats.totalCourses || 0,
        streak: stats.streak || 0,
        lastActivity: stats.lastActivity || null,
        courseProgress: Array.isArray(courseProgress) ? courseProgress.map((cp: any) => ({
          id: cp.id || cp.courseId,
          title: cp.title || cp.courseName || 'Untitled Course',
          progressPercentage: cp.progress || cp.progressPercentage || 0,
          completed: cp.completed || cp.status === 'completed',
        })) : [],
        courseData: [],
        recentActivities: Array.isArray(recentActivities) ? recentActivities : [],
        recentActivity: [],
        achievements: Array.isArray(achievements) ? achievements : [],
        upcomingDeadlines: [],
        studyGroups: [],
        flashcards: { due: 0, mastered: 0, learning: 0, decks: [], stats: { accuracy: 0, sessions: 0, avgTimePerCard: '0s' }, cards: [] },
        weeklyProgress: [],
        performanceTrends: [],
        recommendedStudy: [],
        peerComparison: { yourAverage: 0, cohortAverage: 0, topPerformer: 0, rank: 0, totalStudents: 0 },
        aiInsights: [],
      };
    } catch (error) {
      console.error('Error fetching all progress data:', error);
      toast.error('Failed to load progress data.');
      throw error;
    }
  },

  async updateUnitProgress(
    unitId: string,
    status: 'notStarted' | 'inProgress' | 'completed' | 'failed',
    completionPercentage?: number,
    timeSpentMinutes?: number,
    notes?: string,
    quizScores?: any
  ): Promise<void> {
    try {
      await api.post<void>(`/progress/${unitId}`, {
        status,
        completionPercentage,
        timeSpentMinutes,
        notes,
        quizScores,
      });
    } catch (error) {
      console.error('Error updating unit progress:', error);
      throw error;
    }
  },

  /**
   * Get study sessions for user
   */
  async getStudySessions(userId: string, options?: { courseId?: string; period?: string }): Promise<any[]> {
    try {
      const params = new URLSearchParams();
      if (options?.courseId) params.append('courseId', options.courseId);
      if (options?.period) params.append('period', options.period);

      const response = await api.get<any[]>(`/study-sessions?${params.toString()}`);
      return Array.isArray(response.data) ? response.data : [];
    } catch (error) {
      console.error('Error fetching study sessions:', error);
      return [];
    }
  },

  /**
   * Get study statistics
   */
  async getStudyStatistics(period: 'week' | 'month' | 'year' = 'month'): Promise<any> {
    try {
      const response = await api.get(`/study-sessions/stats/summary?period=${period}`);
      return response.data || {};
    } catch (error) {
      console.error('Error fetching study statistics:', error);
      return {};
    }
  },

  /**
   * Get learning path progress
   */
  async getLearningPathProgress(userId: string): Promise<any[]> {
    try {
      const response = await api.get<any[]>(`/learning-path-progress/user/${userId}`);
      return Array.isArray(response.data) ? response.data : [];
    } catch (error) {
      console.error('Error fetching learning path progress:', error);
      return [];
    }
  },

  /**
   * Get unit progress
   */
  async getUnitProgress(userId: string, courseId?: string): Promise<any[]> {
    try {
      const query = courseId ? `?courseId=${courseId}` : '';
      const response = await api.get<any[]>(`/unit-progress/user/${userId}${query}`);
      return Array.isArray(response.data) ? response.data : [];
    } catch (error) {
      console.error('Error fetching unit progress:', error);
      return [];
    }
  },

  /**
   * Get peer comparison and analytics
   */
  async getPeerComparison(userId: string): Promise<any> {
    try {
      const response = await api.get(`/progress/peer-comparison/${userId}`);
      return response.data || { yourAverage: 0, cohortAverage: 0, topPerformer: 0, rank: 0, totalStudents: 0 };
    } catch (error) {
      console.error('Error fetching peer comparison:', error);
      return { yourAverage: 0, cohortAverage: 0, topPerformer: 0, rank: 0, totalStudents: 0 };
    }
  },

  /**
   * Sync course progress with learning path
   */
  async syncCourseProgress(courseId: string, progressData: { percentage: number; completedItems: number; totalItems: number }): Promise<void> {
    try {
      await api.post('/learning-path-integration/sync-course-progress', {
        courseId,
        progressData,
      });
    } catch (error) {
      console.error('Error syncing course progress:', error);
      // Non-critical - don't throw
    }
  },

  /**
   * Get recommended learning paths
   */
  async getRecommendedPaths(limit: number = 5): Promise<any[]> {
    try {
      const response = await api.get(`/learning-path-integration/recommended-paths?limit=${limit}`);
      return Array.isArray(response.data) ? response.data : [];
    } catch (error) {
      console.error('Error fetching recommended paths:', error);
      return [];
    }
  },
};

