import React, { useEffect, useState, useRef, useCallback } from 'react';
import { useSearch } from '@/features/search/hooks/useSearch';
import Link from 'next/link';

interface SearchResultsProps {
  initialQuery?: string;
  initialFilter?: string;
}

export const SearchResults: React.FC<SearchResultsProps> = ({
  initialQuery = '',
  initialFilter = 'all',
}) => {
  const [query, setQuery] = useState(initialQuery);
  const [filter, setFilter] = useState(initialFilter);
  const [page, setPage] = useState(1);
  const limit = 20;
  const { results, total, loading, search } = useSearch();
  const itemRefs = useRef<Array<HTMLAnchorElement | null>>([]);
  const [focusedIndex, setFocusedIndex] = useState<number | null>(null);

  // Clear item refs when results change
  useEffect(() => {
    itemRefs.current = itemRefs.current.slice(0, results.length);
  }, [results]);

  useEffect(() => {
    if (query) {
      search(query, filter, page, limit);
    } else {
      // clear results if no query
      search('', filter, page, limit);
    }
  }, [query, filter, page, search]);

  // Keyboard navigation: focus management
  const focusItem = useCallback((index: number) => {
    const el = itemRefs.current[index];
    if (el) {
      el.focus();
      setFocusedIndex(index);
    }
  }, []);

  const handleInputKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'ArrowDown' && results.length > 0) {
      e.preventDefault();
      focusItem(0);
    }
  };

  const handleListKeyDown = (e: React.KeyboardEvent<HTMLUListElement>) => {
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      const next = focusedIndex === null ? 0 : Math.min(results.length - 1, focusedIndex + 1);
      focusItem(next);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      const prev = focusedIndex === null ? results.length - 1 : Math.max(0, focusedIndex - 1);
      focusItem(prev);
    } else if (e.key === 'Enter') {
      // Let the focused anchor handle Enter by default
    }
  };

  return (
    <div>
      <div className="mb-4 flex items-center gap-2">
        <label htmlFor="search-input" className="sr-only">
          Search query
        </label>
        <input
          id="search-input"
          type="text"
          value={query}
          onChange={e => {
            setQuery(e.target.value);
            setPage(1);
          }}
          onKeyDown={handleInputKeyDown}
          placeholder="Search for courses, materials, users..."
          aria-label="Search for courses, materials, users"
          className="flex-1 px-3 py-2 border rounded"
        />

        <div>
          <label htmlFor="search-filter" className="sr-only">
            Filter results by type
          </label>
          <select
            id="search-filter"
            value={filter}
            onChange={e => {
              setFilter(e.target.value);
              setPage(1);
            }}
            className="px-2 py-2 border rounded"
            aria-label="Filter results"
          >
            <option value="all">All</option>
            <option value="course">Courses</option>
            <option value="unit">Units</option>
            <option value="topic">Topics</option>
            <option value="material">Materials</option>
            <option value="user">Users</option>
          </select>
        </div>
      </div>

      {loading && <div>Searching…</div>}

      {!loading && (
        <div>
          <div className="text-sm text-gray-600 mb-2">{total} results</div>
          <ul
            className="space-y-2"
            role="listbox"
            aria-label="Search results"
            onKeyDown={handleListKeyDown}
          >
            {results.map((r: any, idx: number) => {
              let href = `/profile/${r.id}`;
              if (r.type === 'course') href = `/courses/${r.id}`;
              else if (r.type === 'material') href = `/materials/${r.id}`;
              else if (r.type === 'unit') href = `/units/${r.id}`;
              else if (r.type === 'topic') href = `/topics/${r.id}`;
              return (
                <li key={`${r.type}-${r.id}`} className="p-3 border rounded">
                  <Link href={href} passHref legacyBehavior>
                    <a
                      ref={el => {
                        itemRefs.current[idx] = el;
                      }}
                      role="option"
                      aria-selected={focusedIndex === idx}
                      tabIndex={-1}
                      className="block focus:outline-none focus:ring-2 focus:ring-blue-500"
                      onFocus={() => setFocusedIndex(idx)}
                    >
                      <div className="font-medium">{r.title}</div>
                      <div className="text-sm text-gray-600">{r.description}</div>
                      <div className="text-xs text-gray-500">Type: {r.type}</div>
                    </a>
                  </Link>
                </li>
              );
            })}
          </ul>

          {/* Pagination */}
          {total > limit && (
            <div className="mt-4 flex items-center justify-between">
              <div className="text-sm text-gray-600">
                Showing page {page} of {Math.ceil(total / limit)}
              </div>
              <div className="space-x-2">
                <button
                  onClick={() => setPage(p => Math.max(1, p - 1))}
                  disabled={page === 1}
                  className="px-3 py-1 border rounded disabled:opacity-50"
                  aria-label="Previous page"
                >
                  Prev
                </button>
                <button
                  onClick={() => setPage(p => Math.min(Math.ceil(total / limit), p + 1))}
                  disabled={page >= Math.ceil(total / limit)}
                  className="px-3 py-1 border rounded disabled:opacity-50"
                  aria-label="Next page"
                >
                  Next
                </button>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

'use client';

import { useCallback, useState, useRef } from 'react';

export function useSearch() {
  const [results, setResults] = useState<any[]>([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(false);
  const abortRef = useRef<AbortController | null>(null);

  const search = useCallback(async (query: string, type: string = 'all', page = 1, limit = 10) => {
    if (abortRef.current) abortRef.current.abort();
    if (!query || query.trim().length === 0) {
      setResults([]);
      setTotal(0);
      return;
    }
    setLoading(true);
    const ctrl = new AbortController();
    abortRef.current = ctrl;

    try {
      const params = new URLSearchParams();
      params.set('query', query);
      if (type && type !== 'all') params.set('type', type);
      params.set('page', String(page));
      params.set('limit', String(limit));

      const res = await fetch(`/api/search?${params.toString()}`, { signal: ctrl.signal });
      if (!res.ok) throw new Error('Search failed');
      const data = await res.json();
      setResults(data.results || []);
      setTotal(data.total || 0);
    } catch (err) {
      if ((err as any).name === 'AbortError') return;
      console.error('Search error', err);
    } finally {
      setLoading(false);
    }
  }, []);

  return { results, total, loading, search } as const;
}

// Search Service - handles API calls to backend search endpoint
export interface SearchResult {
  id: string;
  type: 'course' | 'material' | 'unit' | 'topic' | 'user';
  title: string;
  description?: string;
  relevance: number;
}

export interface SearchResponse {
  results: SearchResult[];
  total: number;
  page: number;
  limit: number;
}

export interface SearchParams {
  query: string;
  type?: 'course' | 'material' | 'unit' | 'topic' | 'user' | 'all';
  page?: number;
  limit?: number;
}

/**
 * Search for courses, materials, units, topics, and users using PostgreSQL full-text search (FTS)
 * @param params - Search parameters (query, type, page, limit)
 * @returns Search results with relevance ranking
 */
export async function searchEntities(params: SearchParams): Promise<SearchResponse> {
  const { query, type = 'all', page = 1, limit = 10 } = params;

  if (!query || query.trim().length === 0) {
    return { results: [], total: 0, page, limit };
  }

  try {
    const searchParams = new URLSearchParams();
    searchParams.set('query', query);
    if (type && type !== 'all') {
      searchParams.set('type', type);
    }
    searchParams.set('page', String(page));
    searchParams.set('limit', String(limit));

    const response = await fetch(`/api/search?${searchParams.toString()}`, {
      method: 'GET',
      headers: {
        'Content-Type': 'application/json',
      },
    });

    if (!response.ok) {
      throw new Error(`Search request failed with status ${response.status}`);
    }

    const data: SearchResponse = await response.json();
    return data;
  } catch (error) {
    console.error('Search service error:', error);
    throw error;
  }
}

/**
 * Perform a quick search with default limit for autocomplete/suggestions
 */
export async function quickSearch(query: string, type?: string): Promise<SearchResult[]> {
  try {
    const response = await searchEntities({
      query,
      type: type as any,
      page: 1,
      limit: 6,
    });
    return response.results;
  } catch (error) {
    console.error('Quick search error:', error);
    return [];
  }
}

/**
 * Get search suggestions based on partial query
 */
export async function getSearchSuggestions(query: string): Promise<string[]> {
  if (!query || query.trim().length < 2) {
    return [];
  }

  try {
    const results = await quickSearch(query);
    // Extract unique titles as suggestions
    const suggestions = Array.from(new Set(results.map(r => r.title))).slice(0, 5);
    return suggestions;
  } catch (error) {
    console.error('Get suggestions error:', error);
    return [];
  }
}

'use client';

import React, { Component, ErrorInfo, ReactNode } from 'react';
import { errorService } from '@/app/services/error.service';

interface Props {
  children: ReactNode;
}

interface State {
  hasError: boolean;
  error?: Error;
}

export class AppErrorBoundary extends Component<Props, State> {
  constructor(props: Props) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    errorService.handleApiError({
      message: error.message,
      status: 0,
      code: 'UI_ERROR',
      details: { errorInfo },
    } as any);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div className="p-6 text-center">
          <h2 className="text-xl font-semibold">Something went wrong.</h2>
          <p className="text-sm text-gray-600 mt-2">Please try again or refresh the page.</p>
        </div>
      );
    }
    return this.props.children;
  }
}

export default AppErrorBoundary;

